INSERT INTO gencine_hadiths (sort_order, title, ar, ku, source, active) VALUES
  (96, 'نیشانێن منافقان', 'عَنْ عَبْدِ الله بْنِ عَمْرٍو رضي الله عنه أَنَّ النَّبِيَّﷺ قَالَ: «أَرْبَعٌ مَنْ كُنَّ فِيهِ كَانَ مُنَافِقًا خَالِصًا، وَمَنْ كَانَتْ فِيهِ خَصْلَةٌ مِنْهُنَّ كَانَتْ فِيهِ خَصْلَةٌ مِنَ النِّفَاقِ حَتَّى يَدَعَهَا: إِذَا اؤْتُمِنَ خَانَ، وَإِذَا حَدَّثَ كَذَبَ، وَإِذَا عَاهَدَ غَدَرَ، وَإِذَا خَاصَمَ فَجَرَ».', 'عه‌بدللاهێ كوڕێ عه‌مرێ كوڕێ عاصى -خودێ ژێ رازى بت- دبێژت: پێغه‌مبه‌رى -سلاڤ لێ بن- گۆت: چار سالۆخه‌ت هه‌نه‌ هه‌چییێ ئه‌و ل نك هه‌بن ئه‌و خوڕى منافقه‌، و هه‌چییێ ئێك ژ وان سالۆخه‌تان ل نك هه‌بت ئه‌وى سالۆخه‌ته‌كێ نیفاقێ ل نك هه‌یه‌: ئه‌گه‌ر ئێكى باوه‌رییا خۆ پێ ئینا ئه‌و خیانه‌تێ بكه‌ت، و ئه‌گه‌ر ئه‌و ئاخفت ئه‌و دره‌وێ بكه‌ت، و ئه‌گه‌ر وى په‌یمانه‌ك دا ئه‌و غه‌درێ بكه‌ت، و ئه‌گه‌ر وى هه‌ڤڕكى كر ئه‌و د سه‌ردادچت.', NULL, true),
  (106, 'نیشانێن منافقان', 'عَنْ أَبِي هُرَيْرَةَ رضي الله عنه عَنِ النَّبِيِّﷺ قَالَ: «آيَةُ المُنَافِقِ ثَلاَثٌ: إِذَا حَدَّثَ كَذَبَ، وَإِذَا وَعَدَ أَخْلَفَ، وَإِذَا اؤْتُمِنَ خَانَ».', 'ئه‌بوو هوره‌یره‌ -خودێ ژێ رازى بت- دبێژت: پێغه‌مبه‌رى -سلاڤ لێ بن- گۆت: نیشانێن منافقى سێنه‌: ئه‌گه‌ر ئه‌و ئاخفت ئه‌و دره‌وێ بكه‌ت، و ئه‌گه‌ر وى په‌یمانه‌ك دا ئه‌و غه‌درێ بكه‌ت، و ئه‌گه‌ر ئێكى باوه‌رییا خۆ پێ ئینا ئه‌و خیانه‌تێ بكه‌ت.', NULL, true),
  (116, 'ڕاستى ڕێكا بەحەشتێیه و درەو ڕێكا جەهنەمێیه', 'عَنْ عَبْدِ الله بن مسعود رضي الله عنه قَالَ: قَالَ رَسُولُ اللهﷺ : «عَلَيْكُمْ بِالصِّدْقِ، فَإِنَّ الصِّدْقَ يَهْدِي إِلَى الْبِرِّ، وَإِنَّ الْبِرَّ يَهْدِي إِلَى الجَنَّةِ، وَمَا يَزَالُ الرَّجُلُ يَصْدُقُ وَيَتَحَرَّى الصِّدْقَ حَتَّى يُكْتَبَ عِنْدَ الله صِدِّيقًا، وَإِيَّاكُمْ وَالْكَذِبَ، فَإِنَّ الْكَذِبَ يَهْدِي إِلَى الْفُجُورِ، وَإِنَّ الْفُجُورَ يَهْدِي إِلَى النَّارِ، وَمَا يَزَالُ الرَّجُلُ يَكْذِبُ وَيَتَحَرَّى الْكَذِبَ حَتَّى يُكْتَبَ عِنْدَ الله كَذَّابًا».', 'عه‌بدللاهێ كوڕێ مه‌سعوودى‌ -خودێ ژێ رازى بت- دبێژت: پێغه‌مبه‌رى -سلاڤ لێ بن- گۆت: وه‌ ئێمانه‌ت ڕاستى، چونكى هندى ڕاستییه‌ به‌رێ خودانى دده‌ته‌ قه‌نجییێ، و هندى قه‌نجییه‌ به‌رێ وى دده‌ته‌ به‌حه‌شتێ، و زه‌لام دێ مینت ڕاستییێ بێژت و ل ڕاستییێ گه‌ڕیێت حه‌تا ئه‌و ل نك خودێ دئێته‌ نڤیسین پڕڕاستگۆ، و هشیارى دره‌وێ بن، چونكى هندى دره‌وه‌ به‌رێ خودانى دده‌ته‌ سه‌رداچوونێ، و سه‌رداچوون به‌رێ وى دده‌ته‌ ئاگرى، و زه‌لام دێ مینت دره‌وێ كه‌ت و ل دره‌وێ گه‌ڕیێت حه‌تا ئه‌و ل نك خودێ دئێته‌ نڤیسین پڕدره‌وین.', NULL, true),
  (126, 'خرابترین مرۆڤ كەسێ دوڕوییه', 'عَنْ أَبِي هُرَيْرَةَ رضي الله عنه عَنْ رَسُولِ اللهﷺ قَالَ: «تَجِدُونَ النَّاسَ مَعَادِنَ، خِيَارُهُمْ فِي الجَاهِلِيَّةِ خِيَارُهُمْ فِي الإِسْلاَمِ إِذَا فَقِهُوا، وَتَجِدُونَ خَيْرَ النَّاسِ فِي هَذَا الشَّأْنِ أَشَدَّهُمْ لَهُ كَرَاهِيَةً، وَتَجِدُونَ شَرَّ النَّاسِ ذَا الْوَجْهَيْنِ، الَّذِي يَأْتِي هَؤُلاَءِ بِوَجْهٍ وَيَأْتِي هَؤُلاَءِ بِوَجْهٍ».', 'ئه‌بوو هوره‌یره‌‌ -خودێ ژێ رازى بت- دبێژت: پێغه‌مبه‌رى -سلاڤ لێ بن- گۆت: هوین دبینن مرۆڤ مه‌عده‌نن (یه‌عنى: د بناخه‌یێ خۆ دا ئه‌و دژێك جودانه‌) باشێ وان د جاهلییه‌تێ دا باشێ وانه‌ د ئیسلامێ دا ئه‌گه‌ر زانابوو، و هوین دبینن باشترینێ مرۆڤان بۆ ڤى كارى (یه‌عنى: مه‌زنى و به‌رپڕسییێ) ئه‌وه‌ یێ ژ هه‌مییان پتر ئه‌و نه‌ڤێت، و هوین دبینن خرابترینێ مرۆڤان دوڕوییه‌، ئه‌وێ ب ڕوییه‌كێ دئێته‌ نك ڤان، و ب ڕوییه‌كى دئێته‌ نك ڤان.', NULL, true),
  (136, 'خودێ ل دویڤ زۆردارى بەرددەت حەتا وى دگرت', 'عَنْ أَبِي موسى رضي الله عنه قَالَ: قال رَسُولُ اللهﷺ : «إِنَّ الله لَيُمْلِي لِلظَّالِمِ حَتَّى إِذَا أَخَذَهُ لَمْ يُفْلِتْهُ» قَالَ: ثُمَّ قَرَأَ: «وَكَذَٰلِكَ أَخۡذُ رَبِّكَ إِذَآ أَخَذَ ٱلۡقُرَىٰ وَهِيَ ظَٰلِمَةٌۚ إِنَّ أَخۡذَهُۥٓ أَلِيمٞ شَدِيدٌ ١٠٢».', 'ئه‌بوو هوره‌یره‌‌ -خودێ ژێ رازى بت- دبێژت: پێغه‌مبه‌رى -سلاڤ لێ بن- گۆت: هندى خودێیه‌ ل دویڤ زۆردارى به‌ردده‌ت، حه‌تا ئه‌گه‌ر وى ئه‌و گرت ئه‌و ژێ خلاص نابت، پاشى وى ئه‌ڤ ئایه‌ته‌ خواند ئه‌وا تێدا هاتى: گرتنا خودایێ ته‌ ب خه‌لكێ باژێڕان یا هۆسایه‌ ده‌مێ ئه‌و زۆردارییێ دكه‌ن، هندى گرتنا وییه‌ یا ب ئێش و دژواره‌.', NULL, true),
  (146, 'پشتەڤانییا ته بۆ زۆردارى ئەوه تو نەهێلى ئەو زۆردارییێ بكەت', 'عَنْ أَنَسٍ رضي الله عنه قَالَ: قَالَ رَسُولُ اللهﷺ : «انْصُرْ أَخَاكَ ظَالِمًا، أَوْ مَظْلُومًا» فَقَالَ رَجُلٌ: يَا رَسُولَ الله، أَنْصُرُهُ إِذَا كَانَ مَظْلُومًا أَفَرَأَيْتَ إِذَا كَانَ ظَالِمًا كَيْفَ أَنْصُرُهُ؟ قَالَ: «تَحْجُزُهُ، أَوْ تَمْنَعُهُ مِنَ الظُّلْمِ فَإِنَّ ذَلِكَ نَصْرُهُ».', 'ئه‌نه‌س -خودێ ژێ رازى بت- دبێژت: پێغه‌مبه‌رى -سلاڤ لێ بن- گۆت: تو پشته‌ڤانییا برایێ خۆ بكه‌ چ ئه‌و یێ زۆردار بت، چ زۆردارى لێ هاتبته‌كرن. زه‌لامه‌كى گۆت: ئه‌ى پێغه‌مبه‌رێ خودێ، ئه‌ز دێ پشته‌ڤانییا وى كه‌م ئه‌گه‌ر زۆردارى ل وى هاتبته‌كرن، به‌لێ پا ئه‌گه‌ر ئه‌و یێ زۆردار بت، چاوا ئه‌ز دێ پشته‌ڤانییا وى كه‌م؟ وى گۆت: تو دێ وى ژ زۆردارییێ گرى ئه‌وه‌ پشته‌ڤانییا ته‌ بۆ وى.', NULL, true),
  (156, 'موسلمانێ دورست كیە؟ و مشەختێ دورست كیە؟', 'عَنْ عَبْدِ الله بْنِ عَمْرٍو رضي الله عنه عَنِ النَّبِيِّﷺ قَالَ : «المُسْلِمُ مَنْ سَلِمَ المُسْلِمُونَ مِنْ لِسَانِهِ وَيَدِهِ، وَالمُهَاجِرُ مَنْ هَجَرَ مَا نَهَى الله عَنْهُ».', 'عه‌بدللاهێ كوڕێ عه‌مرى -خودێ ژ هه‌ردویان رازى بت- دبێژت: پێغه‌مبه‌رى -سلاڤ لێ بن- گۆت: موسلمان ئه‌وه‌ یێ موسلمان ژ ئه‌زمانێ وى و ده‌ستێ وى دپارستى بن، و مشه‌خت ئه‌وه‌ یێ پشت بده‌ته‌ وى یێ یێ خودێ نه‌هى ژێ كرى.', NULL, true),
  (166, 'سالۆخەتێن موسلمانێ دورست', 'عَنِ عَبْدِ الله بْنِ عُمَرَ رضي الله عنه أَنَّ رَسُولَ اللهﷺ قَالَ: «المُسْلِمُ أَخُو المُسْلِمِ لاَ يَظْلِمُهُ، وَلاَ يُسْلِمُهُ، وَمَنْ كَانَ فِي حَاجَةِ أَخِيهِ كَانَ الله فِي حَاجَتِهِ، وَمَنْ فَرَّجَ عَنْ مُسْلِمٍ كُرْبَةً فَرَّجَ الله عَنْهُ كُرْبَةً مِنْ كُرُبَاتِ يَوْمِ الْقِيَامَةِ، وَمَنْ سَتَرَ مُسْلِمًا سَتَرَهُ الله يَوْمَ الْقِيَامَةِ».', 'عه‌بدللاهێ كوڕێ عومه‌رى -خودێ ژ هه‌ردویان رازى بت- دبێژت: پێغه‌مبه‌رى -سلاڤ لێ بن- گۆت: موسلمان برایێ موسلمانییه‌ زۆردارییێ لێ ناكه‌ت، و وى ته‌سلیمى دوژمنى ناكه‌ت، و هه‌چییێ د خێرا برایێ خۆ دا بت خودێ دێ د خێرا وى دا بت، و هه‌چییێ ته‌نگاڤییه‌كێ ژ سه‌ر موسلمانه‌كى ڕاكه‌ت خودێ ته‌نگاڤییه‌كێ ژ ته‌نگاڤییێن ڕۆژا قیامه‌تێ دێ ژ سه‌ر وى ڕاكه‌ت، و هه‌چییێ موسلمانه‌كى ستاره‌ بكه‌ت ڕۆژا قیامه‌تێ خودێ دێ وى ستاره‌ كه‌ت.', NULL, true),
  (176, 'حەفت ئەمر و حەفت نەهى', 'قَالَ الْبَرَاءُ بْنُ عَازِبٍ رضي الله عنه : أَمَرَنَا النَّبِيُّﷺ بِسَبْعٍ وَنَهَانَا عَنْ سَبْعٍ، أَمَرَنَا بِعِيَادَةِ المَرِيضِ، وَاتِّبَاعِ الْجِنَازَةِ، وَتَشْمِيتِ الْعَاطِسِ، وَإِبْرَارِ الْقَسَمِ، وَنَصْرِ المَظْلُومِ، وَإِفْشَاءِ السَّلاَمِ، وَإِجَابَةِ الدَّاعِي، وَنَهَانَا عَنْ خَوَاتِيمِ الذَّهَبِ، وَعَنْ آنِيَةِ الْفِضَّةِ، وَعَنِ المَيَاثِرِ، وَالْقَسِّيَّةِ، وَالإِسْتَبْرَقِ، وَالدِّيبَاجِ.', 'به‌ررائێ كوڕێ عازبى -خودێ ژێ رازى بت- دبێژت: پێغه‌مبه‌رى -سلاڤ لێ بن- فه‌رمان ب حه‌فت تشتان ل مه‌ كر، و ئه‌م ژ حه‌فت تشتان داینه‌ پاش، وى فه‌رمان ب سه‌ره‌دانا نه‌خۆشان ل مه‌ كر و دویكه‌فتنا جه‌نازه‌یان، و به‌رسڤدانا وى یێ دبێنژت، و نه‌شكاندنا سویندا وى یێ مرۆڤى دده‌ته‌ سویندێ، و پشته‌ڤانییا وى یێ سته‌م لێ دئێته‌كرن، و به‌لاڤكرنا سلاڤێ، و چوونا د به‌رسڤا وى یێ مرۆڤى ڤه‌خوینت، و وى ئه‌م ل به‌رخۆكرنا گوستیركێن زێڕى داینه‌ پاش، و خوارنا د ئامانێن زیڤى دا، و جلێن ده‌واران ئه‌وێن ژ ئاڤرمیشى دئێنه‌ چێكرن، و كراسێن ئاڤرمیشى، و كراسێن ئیسته‌بره‌ق و دیباجى (و ئه‌و ژى دو ڕه‌نگێن ئاڤرمیشینه‌).', NULL, true),
  (186, 'خودان باوەر خودان باوەرى دگرت', 'عَنْ أَبِي مُوسَى رضي الله عنه عَنِ النَّبِيِّﷺ قَالَ: «إِنَّ المُؤْمِنَ لِلْمُؤْمِنِ كَالْبُنْيَانِ يَشُدُّ بَعْضُهُ بَعْضًا» وَشَبَّكَ أَصَابِعَهُ.', 'ئه‌بوو مووسا -خودێ ژێ رازى بت- دبێژت: پێغه‌مبه‌رى -سلاڤ لێ بن- گۆت: خودان باوه‌ر بۆ خودان باوه‌رى وه‌كى ئاڤاهییه‌ هنده‌ك هنده‌كێ دگرت. و وى تبلێن خۆ كرنه‌ د ناڤێك ڕا.', NULL, true),
  (196, 'مەتەلا خودان باوەران', 'عَنِ النُّعْمَانِ بْنِ بَشِيرٍ رضي الله عنه قَالَ: قَالَ رَسُولُ اللهﷺ : «مَثَلُ المُؤْمِنِينَ فِي تَوَادِّهِمْ، وَتَرَاحُمِهِمْ، وَتَعَاطُفِهِمْ، مَثَلُ الجَسَدِ إِذَا اشْتَكَى مِنْهُ عُضْوٌ تَدَاعَى لَهُ سَائِرُ الجَسَدِ بِالسَّهَرِ وَالحُمَّى».', 'نوعمانێ كوڕێ به‌شیرى -خودێ ژێ رازى بت- دبێژت: پێغه‌مبه‌رى -سلاڤ لێ بن- گۆت: مه‌ته‌لا خودان باوه‌ران د ڤیان و ره‌حم و دلۆڤانییا وان دا، وه‌كى مه‌ته‌لا له‌شییه‌، ئه‌گه‌ر ئه‌ندامه‌ك ژێ ئێشا له‌ش هه‌مى تاگرتى دبت و خه‌و ب چاڤان ناكه‌ڤت.', NULL, true),
  (206, 'دو ڕەنگێن دورست یێن حەسویدییێ', 'عَنْ عَبْدِ الله بْنِ مَسْعُودٍ رضي الله عنه يَقُولُ: قَالَ رَسُولُ اللهﷺ : «لاَ حَسَدَ إِلاَّ فِي اثْنَتَيْنِ: رَجُلٌ آتَاهُ الله مَالاً، فَسَلَّطَهُ عَلَى هَلَكَتِهِ فِي الحَقِّ، وَرَجُلٌ آتَاهُ الله حِكْمَةً، فَهُوَ يَقْضِي بِهَا وَيُعَلِّمُهَا».', 'عه‌بدللاهێ كوڕێ مه‌سعوودى -خودێ ژێ رازى بت- دبێژت: پێغه‌مبه‌رى -سلاڤ لێ بن- گۆت: حه‌سویدى چێ نابت، یا دو مرۆڤان تێ نه‌بت: زه‌لامه‌كى خودێ ماله‌كێ دایێ ڤێجا ئه‌و وى د حه‌قییێ دا خه‌رج دكه‌ت، و زه‌لامه‌كى خودێ زانینا (قورئانێ) یا دایێ ڤێجا ئه‌و حوكمى پێ دكه‌ت، و وێ نیشا خه‌لكى دده‌ت.', NULL, true),
  (216, 'ژ سالۆخەتێن بەحەشتى و جەهنەمییان', 'عَن حَارِثَةَ بْنِ وَهْبٍ الخُزَاعِيِّ رضي الله عنه قَالَ: سَمِعْتُ النَّبِيَّﷺ يَقُولُ: «أَلَا أُخْبِرُكُمْ بِأَهْلِ الجَنَّةِ؟ كُلُّ ضَعِيفٍ مُتَضَعِّفٍ لَوْ أَقْسَمَ عَلَى الله لَأَبَرَّهُ، أَلَا أُخْبِرُكُمْ بِأَهْلِ النَّارِ؟ كُلُّ عُتُلٍّ جَوَّاظٍ مُسْتَكْبِرٍ».', 'حارثه‌یێ كوڕێ وه‌هه‌بێ خوزاعى -خودێ ژێ رازى بت- دبێژت: پێغه‌مبه‌رى -سلاڤ لێ بن- گۆت: ئه‌رێ ئه‌ز بۆ هه‌وه‌ به‌حسێ به‌حه‌شتییان نه‌كه‌م كینه‌؟ هه‌ر لاوه‌زه‌كێ خه‌لك وى لاواز دبینن، ئه‌گه‌ر ئه‌و خودێ بده‌ته‌ سویندێ خودێ سویندا وى دێ ب جهـ ئینت، و ئه‌ز بۆ هه‌وه‌ به‌حسێ جه‌هنه‌مییان نه‌كه‌م؟ هه‌ر كه‌سێ زڤڕ و ڕه‌ق و خۆ مه‌زن دكه‌ت.', NULL, true),
  (226, 'دا كو نعمەتا خودێ كێم نەكەى', 'عَنْ أَبِي هُرَيْرَةَ رضي الله عنه قَالَ: قَالَ رَسُولُ اللهﷺ : «انْظُرُوا إِلَى مَنْ أَسْفَلَ مِنْكُمْ، وَلاَ تَنْظُرُوا إِلَى مَنْ هُوَ فَوْقَكُمْ، فَهُوَ أَجْدَرُ أَنْ لاَ تَزْدَرُوا نِعْمَةَ الله».', 'ئه‌بوو هوره‌یره‌ -خودێ ژێ رازى بت- دبێژت: پێغه‌مبه‌رى -سلاڤ لێ بن- گۆت: به‌رێ خۆ بده‌نه‌ یێن د بن خۆ دا، و به‌رێ خۆ نه‌ده‌نه‌ یێن د سه‌ر خۆ دا، ئه‌و هه‌ژیتره‌ كو هوین نعمه‌تا خودێ كێم نه‌كه‌ن.', NULL, true),
  (236, 'دو گونەهێن مرۆڤ د قەبرى دا پێ دئێته عەزابدان', 'عَنْ ابْنِ عَبَّاسٍ رضي الله عنه قَالَ مَرَّ النَّبِيُّﷺ بِقَبْرَيْنِ فَقَالَ: «إِنَّهُمَا لَيُعَذَّبَانِ وَمَا يُعَذَّبَانِ فِي كَبِيرٍ، أَمَّا أَحَدُهُمَا فَكَانَ لَا يَسْتَتِرُ مِنْ الْبَوْلِ، وَأَمَّا الْآخَرُ فَكَانَ يَمْشِي بِالنَّمِيمَةِ».', 'ئبن عه‌بباس -خودێ ژ هه‌ردویان رازى بت- دبێژت: پێغه‌مبه‌ر -سلاڤ لێ بن- د به‌ر دو قه‌بران ڕا بۆرى، و گۆت: ئه‌و هه‌ردو یێن دئێنه‌ عه‌زابدان، و ئه‌و نه‌ ژ به‌ر تشته‌كێ مه‌زن دئێنه‌ عه‌زابدان، ئێك ژ وان خۆ ژ ده‌سنڤێژا زراڤ نه‌دپاراست، و یێ دى قه‌سه‌ ڤه‌دگوهازتن.', NULL, true),
  (246, 'قەسەڤەگوهێز ناچته بەحەشتێ', 'قَالَ حُذَيْفَةُ رضي الله عنه : سَمِعْتُ رَسُولَ اللهﷺ يَقُولُ: «لاَ يَدْخُلُ الجَنَّةَ نَمَّامٌ».', 'حوذه‌یفه‌ -خودێ ژێ رازى بت- دبێژت: پێغه‌مبه‌رى -سلاڤ لێ بن- گۆت: قه‌سه‌ڤه‌گوهێز ناچته‌ به‌حه‌شتێ.
INSERT INTO gencine_hadiths (sort_order, title, ar, ku, source, active) VALUES
  (296, 'كیژ موسلمانەتى باشترە؟', 'عَنْ عَبْدِ الله بْنِ عَمْرٍو رضي الله عنه أَنَّ رَجُلًا سَأَلَ النَّبِيَّﷺ : أَيُّ الْإِسْلَامِ خَيْرٌ؟ قَالَ: «تُطْعِمُ الطَّعَامَ، وَتَقْرَأُ السَّلَامَ عَلَى مَنْ عَرَفْتَ وَمَنْ لَمْ تَعْرِف».', 'عه‌بدللاهێ كوڕێ عه‌مرى -خودێ ژ هه‌ردویان رازى بت- دبێژت: زه‌لامه‌كى پسیار ژ پێغه‌مبه‌رى -سلاڤ لێ بن- كر: كیژ موسلمانه‌تى چێتره‌؟ وى گۆت: كو تو خوارنێ بده‌ى، و سلاڤێ بده‌یه‌ وى یێ تو دنیاسى، و وى یێ تو نه‌نیاسى ژى.', NULL, true),
  (306, 'ژ پێتڤییێن باوەرییا ب خودێ و ڕۆژا دووماهییێ', 'عَنْ أَبِي هُرَيْرَةَ رضي الله عنه عَنْ النَّبِيِّﷺ قَالَ: «مَنْ كَانَ يُؤْمِنُ بِالله وَالْيَوْمِ الْآخِرِ فَلْيُكْرِمْ ضَيْفَهُ، وَمَنْ كَانَ يُؤْمِنُ بِالله وَالْيَوْمِ الْآخِرِ فَلْيَصِلْ رَحِمَهُ، وَمَنْ كَانَ يُؤْمِنُ بِالله وَالْيَوْمِ الْآخِرِ فَلْيَقُلْ خَيْرًا أَوْ لِيَصْمُتْ».', 'ئه‌بوو هوره‌یره‌ -خودێ ژێ رازى بت- دبێژت: پێغه‌مبه‌رى -سلاڤ لێ بن- گۆت: هه‌چییێ باوه‌رى ب خودێ و ڕۆژا دووماهییێ هه‌بت بلا قه‌درێ مێڤانی خۆ بگرت، و هه‌چییێ باوه‌رى ب خودی و ڕۆژا دووماهییێ هه‌بت بلا یێ ب مرۆڤاینى بت، و هه‌چییێ باوه‌رى ب خودی و ڕۆژا دووماهییێ هه‌بت بلا خێرێ بێژت یان خۆ بێ ده‌نگ بكه‌ت.', NULL, true),
  (316, 'سوننەتا دەستویردانێ', 'عَنْ أَبِي مَسْعُودٍ الأَنْصَارِيِّ رضي الله عنه قَالَ: دعَا رَجُلٌ النَّبيَّﷺ لِطَعامٍ صَنَعَهُ خامِسَ خمسَةٍ، وأتْبَعَهُمْ رجلٌ، فلما بَلَغَ البابَ، قال النَّبِيُّﷺ : «إِنَّ هَذَا اتَّبَعَنَا، فَإِنْ شِئْتَ أَنْ تَأْذَنَ لَهُ، وَإِنْ شِئْتَ رَجَعَ» قَالَ: لاَ، بَلْ آذَن لَهُ يَا رَسُولَ الله.', 'ئه‌بوو مه‌سعوودێ ئه‌نصارى -خودێ ژێ رازى بت- دبێژت: زه‌لامه‌كى پێغه‌مبه‌ر -سلاڤ لێ بن- د گه‌ل چار كه‌سان ڤه‌خوانده‌ مالا خۆ، و زه‌لامه‌ك ب دویڤ وان كه‌فت، ده‌مێ ئه‌و گه‌هشتییه‌ به‌ر ده‌رگه‌هى، پێغه‌مبه‌رى -سلاڤ لێ بن- گۆت: ئه‌ڤه‌ یێ ب دویڤ مه‌ كه‌فتى، ئه‌گه‌ر تو حه‌ز بكه‌ى ده‌ستویرییێ بدێ، و ئه‌گه‌ر تو حه‌ز بكه‌ى ئه‌و دێ زڤڕت. وى گۆت: نه‌، ئه‌ز دێ ده‌ستویرییێ ده‌مێ ئه‌ى پێغه‌مبه‌رێ خودێ.', NULL, true),
  (326, NULL, 'عن أَبي مُوسَى الأَشْعَرِيِّ رضي الله عنه قَالَ: قَالَ رَسُولُ اللهﷺ : «الاِسْتِئْذَانُ ثَلاَثٌ، فَإِنْ أُذِنَ لَكَ وَإِلاَّ فَارْجِعْ».', 'ئه‌بوو مووسایێ ئه‌شعه‌رى -خودێ ژێ رازى بت- دبێژت: پێغه‌مبه‌رى -سلاڤ لێ بن- گۆت: خواستنا ده‌ستویرییێ سێ جارانه‌، ڤێجا ئه‌گه‌ر ده‌ستویرى بۆ ته‌ هاته‌دان هه‌ڕه‌، ئه‌گه‌ر نه‌ بزڤڕه‌ڤه‌.', NULL, true),
  (336, 'ئەوێ جیرانێ وى یێ ژێ ئەمین نەبت', 'عَنْ أَبِي هريرة رضي الله عنه أَنَّ النَّبِيَّﷺ قَالَ: «وَالله لَا يُؤْمِنُ، وَالله لَا يُؤْمِنُ، وَالله لَا يُؤْمِنُ» قِيلَ: وَمَنْ يَا رَسُولَ الله؟ قَالَ: «الَّذِي لَا يَأْمَنُ جَارُهُ بَوَايِقَهُ».', 'ئه‌بوو هوره‌یره‌ -خودێ ژێ رازى بت- دبێژت: پێغه‌مبه‌رى -سلاڤ لێ بن- گۆت: ب خودێ ئه‌و باوه‌رییێ نائینت، ب خودێ ئه‌و باوه‌رییێ نائینت، ب خودێ ئه‌و باوه‌رییێ نائینت، گۆتن: و ئه‌و كییه‌ ئه‌ى پێغه‌مبه‌رێ خودێ؟ گۆت: ئه‌وێ جیرانێ وى یێ ژ خرابییێن وى ئه‌مین نه‌بت.', NULL, true),
  (346, 'ئەوێ بێ دەستویرى بەرێ خۆ بدەته مالەكێ', 'عَنْ أَبِي هُرَيْرَةَ رضي الله عنه عَنِ النَّبِيِّﷺ قَالَ: «مَنِ اطَّلَعَ فِي بَيْتِ قَوْمٍ بِغَيْرِ إِذْنِهِمْ، فَقَدْ حَلَّ لَهُمْ أَنْ يَفْقَؤُوا عَيْنَهُ».', 'ئه‌بوو هوره‌یره‌ -خودێ ژێ رازى بت- دبێژت: پێغه‌مبه‌رى -سلاڤ لێ بن- گۆت: هه‌چییێ به‌رێ خۆ بده‌ته‌ ماله‌كێ بێى ده‌ستویرییا وان، بۆ وان هه‌یه‌ ئه‌و چاڤێن وى بیننه‌ ده‌ر.', NULL, true),
  (356, 'دەولەمەندێ دەینێ خۆ نەدەت زۆرداره', 'عَنْ أَبِي هُرَيْرَةَ رضي الله عنه أَنَّ رَسُولَ اللهﷺ قَالَ: «مَطْلُ الْغَنِيِّ ظُلْمٌ، فَإِذَا أُتْبِعَ أَحَدُكُمْ عَلَى مَلِيٍّ فَلْيَتْبَعْ».', 'ئه‌بوو هوره‌یره‌ -خودێ ژێ رازى بت- دبێژت: پێغه‌مبه‌رى -سلاڤ لێ بن- گۆت: نه‌دانا ده‌وله‌مه‌ندى بۆ ده‌ینێ خۆ زۆردارییه‌، و ئه‌گه‌ر ئێك بۆ كه‌سه‌كێ تێر و تژى هاته‌ حه‌واله‌كرن، بلا ئه‌و ب وێ حه‌والێ بكه‌ت.', NULL, true),
  (366, 'ئەوێ ژ دیارییا خۆ لێڤه ببت', 'عَنْ ابْنِ عَبَّاسٍ رضي الله عنه قَالَ: قَالَ النَّبِيُّﷺ : «الْعَائِدُ فِي هِبَتِهِ كَالْكَلْبِ يَقِيءُ ثُمَّ يَعُودُ فِي قَيْئِهِ».', 'ئبن عه‌بباس -خودێ ژ هه‌ردویان رازى بت- دبێژت: پێغه‌مبه‌رى -سلاڤ لێ بن- گۆت: ئه‌وێ ل خه‌لات و دیارییا خۆ لێڤه‌ دبت، وه‌كى صه‌یه‌ دلێ خۆ ڕادكه‌ت و لێ دزڤڕته‌ڤه‌.', NULL, true),
  (376, 'خێرا چاندنێ', 'عَنْ أَنَسِ بْنِ مَالِكٍ رضي الله عنه قَالَ: قَالَ رَسُولُ اللهﷺ : «مَا مِنْ مُسْلِمٍ يَغْرِسُ غَرْسًا، أَوْ يَزْرَعُ زَرْعًا، فَيَأْكُلُ مِنْهُ طَيْرٌ، أَوْ إِنْسَانٌ، أَوْ بَهِيمَةٌ إِلَّا كَانَ لَهُ بِهِ صَدَقَةٌ».', 'ئه‌نه‌سێ كوڕێ مالكى -خودێ ژێ رازى بت- دبێژت: پێغه‌مبه‌رى -سلاڤ لێ بن- گۆت: هه‌ر موسلمانه‌كێ شتله‌كێ د عه‌ردى ڕا بكه‌ت، یان داره‌كێ (ژ تۆڤى) بچینت، ڤێجا طه‌یره‌ك یان مرۆڤه‌ك، یان حه‌یوانه‌ك ژێ بخۆت، ئه‌و دێ بۆ وى بته‌ خێر.', NULL, true),
  (386, 'هەڤڕكییەكا د ئەمانەتى دا', 'عَنْ أَبِي هُرَيْرَةَ رضي الله عنه قَالَ: قَالَ النَّبِيُّﷺ : «اشْتَرَى رَجُلٌ مِنْ رَجُلٍ عَقَارًا لَهُ، فَوَجَدَ الرَّجُلُ الَّذِي اشْتَرَى الْعَقَارَ فِي عَقَارِهِ جَرَّةً فِيهَا ذَهَبٌ، فَقَالَ لَهُ الَّذِي اشْتَرَى الْعَقَارَ: خُذْ ذَهَبَكَ مِنِّي إِنَّمَا اشْتَرَيْتُ مِنْكَ الْأَرْضَ، وَلَمْ أَبْتَعْ مِنْكَ الذَّهَبَ، وَقَالَ الَّذِي لَهُ الْأَرْضُ: إِنَّمَا بِعْتُكَ الْأَرْضَ وَمَا فِيهَا، فَتَحَاكَمَا إِلَى رَجُلٍ فَقَالَ الَّذِي تَحَاكَمَا إِلَيْهِ: أَلَكُمَا وَلَدٌ؟ قَالَ أَحَدُهُمَا: لِي غُلَامٌ، وَقَالَ الْآخَرُ: لِي جَارِيَةٌ، قَالَ: أَنْكِحُوا الْغُلَامَ الجَارِيَةَ، وَأَنْفِقُوا عَلَى أَنْفُسِهِمَا مِنْهُ، وَتصَدَّقَا».', 'ئه‌بوو هوره‌یره‌ -خودێ ژێ رازى بت- دبێژت: پێغه‌مبه‌رى -سلاڤ لێ بن- گۆت: زه‌لامه‌كى پارچه‌یه‌كا عه‌رده‌كى ژ ئێكى كڕى، و جه‌ڕكه‌كێ زێڕى د عه‌ردى ڕا دیت، بكڕێ عه‌ردى گۆته‌ خودانێ عه‌ردى: زێڕێ خۆ ببه‌، من عه‌ردى یێ ژ ته‌ كڕى نه‌ زێڕ، خودانێ عه‌ردى گۆتێ: من عه‌رد ب وى تشتى ڤه‌ یێ فرۆتییه‌ ته‌ یێ د ناڤ دا، ڤێجا وان حوكمێ خۆ بره‌ نك زه‌لامه‌كى، وى زه‌لامى گۆته‌ وان: هه‌وه‌ عه‌یال هه‌یه‌؟ ئێكى گۆت: من كوڕه‌كێ هه‌ى، یێ دى گۆت: من كچه‌كا هه‌ى، زه‌لامى گۆتێ: وێ كچێ بده‌نه‌ وى كوڕى، و وى مالى ل وان خه‌رج بكه‌ن، و خێرێ ژێ بده‌ن.', NULL, true),
  (396, 'زەلامێ ژ هەمییان پتر خودێ حەز ژێ ناكەت', 'عَنْ عَائِشَةَ -رَضِيَ الله عَنْهَا- عَنْ النَّبِيِّﷺ قَالَ: «إِنَّ أَبْغَضَ الرِّجَالِ إِلَى الله الْأَلَدُّ الخَصِمُ».', 'عائیشا -خودێ ژێ رازى بت- دبێژت: پێغه‌مبه‌رى -سلاڤ لێ بن- گۆت: زه‌لامێ ژ هه‌مییان پتر خودێ حه‌ز ژێ ناكه‌ت، هه‌ڤڕكێ دژواره‌.', NULL, true),
  (406, 'زیرەك ئەوه یێ بشێته خۆ', 'عَنْ أَبِي هُرَيْرَةَ رضي الله عنه أَنَّ رَسُولَ اللهﷺ قَالَ: «لَيْسَ الشَّدِيدُ بِالصُّرَعَةِ، إِنَّمَا الشَّدِيدُ الَّذِي يَمْلِكُ نَفْسَهُ عِنْدَ الْغَضَبِ».', 'ئه‌بوو هوره‌یره‌ -خودێ ژێ رازى بت- دبێژت: پێغه‌مبه‌رى -سلاڤ لێ بن- گۆت: زیره‌ك ئه‌و نینه‌ یێ ب خۆلێكدانێ یێ زیره‌ك بت، هه‌ما یێ زیره‌ك ئه‌وه‌ یێ ل ده‌مێ كه‌ربێ بشێته‌ خۆ.', NULL, true),
  (416, 'هندەك گونەهێن مەزن', 'عَنْ ثَابِتِ بْنَ الضَّحَّاكِ رضي الله عنه أَنَّ رَسُولَ اللهﷺ قَالَ: «مَنْ حَلَفَ عَلَى يَميْنٍ بمِلَّةٍ غَيْرِ الإِسْلاَمِ كاذبًا فَهْوَ كَمَا قَالَ، وَمَنْ قَتَلَ نَفْسَهُ بِشَيْءٍ فِي الدُّنْيَا عُذِّبَ بِهِ يَوْمَ الْقِيَامَةِ، وَلَيْسَ عَلَى رَجُلٍ نَذْرٌ فِيمَا لاَ يَمْلِكُه» زاد في رواية: «وَلَعْنُ المُؤْمِنِ كَقَتْلِهِ، وَمَنْ رَمَى مُؤْمِنًا بِكُفْرٍ فَهْوَ كَقَتْلِهِ».', 'ثابتێ كوڕێ ضه‌ححاكى -خودێ ژێ رازى بت- دبێژت: پێغه‌مبه‌رى -سلاڤ لێ بن- گۆت: هه‌چییێ ژ دره‌و سوینده‌كێ بخۆت (و بێژت: ئه‌گه‌ر وه‌سا نه‌بت ئه‌و ل سه‌ر فلان دینى بت ژ بلى ئیسلامێ) ئه‌و دێ وه‌سا بت وه‌كى وى گۆتى، و هه‌چییێ د دنیایێ دا خۆ ب تشته‌كى بكوژت ڕۆژا قیامه‌تێ ئه‌و دێ ب وى تشتى ئێته‌ عه‌زابدان، و چو نه‌زر ل سه‌ر زه‌لامى نینه‌ د وى تشتى دا یێ وى نه‌بت. و د ریوایه‌ته‌كا دى دا زێده‌ دكه‌ت و دبێژت: له‌عن باراندن ل خودان باوه‌رى وه‌كى كوشتنا وییه‌، و هه‌چییێ خودان باوه‌ره‌كى كافر بكه‌ت، ئه‌و وه‌كى كوشتنا وییه‌.', NULL, true),
  (426, 'چێ نابت كەس مرنێ بخوازت', 'عَنْ أَنَسِ بْنِ مَالِكٍ رضي الله عنه قَالَ: قال النَّبِيُّﷺ : «لَا يَتَمَنَّيَنَّ أَحَدُكُمْ المَوْتَ مِنْ ضُرٍّ أَصَابَهُ، فَإِنْ كَانَ لَا بُدَّ فَاعِلًا فَلْيَقُلْ: اللهمَّ أَحْيِنِي مَا كَانَتْ الحَيَاةُ خَيْرًا لِي، وَتَوَفَّنِي إِذَا كَانَتْ الْوَفَاةُ خَيْرًا لِي».', 'ئه‌نه‌سێ كوڕێ مالكى -خودێ ژێ رازى بت- دبێژت: پێغه‌مبه‌رى -سلاڤ لێ بن- گۆت: ئێك ژ هه‌وه‌ ژ به‌ر نه‌خۆشییه‌كا گه‌هشتییێ بلا داخوازا مرنێ نه‌كه‌ت، و ئه‌گه‌ر وى چو ڕێ نه‌بت و دڤێت وه‌ بكه‌ت، بلا ئه‌و بێژت: ئه‌ى خودا تو من بهێله‌ زێندى هندى ژیان بۆ من یا ب خێرتر بت، و تو من بمرینه‌ ئه‌گه‌ر مرن بۆ من ب خێرتر بت.', NULL, true),
  (436, 'گرنگییا ئەخلاقێ باش', 'عَنْ عَبْدِ الله بْنِ عَمْرٍو رضي الله عنه قَالَ: لَمْ يَكُنْ النَّبِيُّﷺ فَاحِشًا وَلَا مُتَفَحِّشًا، وَكَانَ يَقُولُ: «إِنَّ مِنْ خِيَارِكُمْ أَحْسَنَكُمْ أَخْلَاقًا».', 'عه‌بدللاهێ كوڕێ عه‌مرى -خودێ ژ هه‌ردویان رازى بت- دبێژت: پێغه‌مبه‌ر -سلاڤ لێ بن- مرۆڤه‌كێ فه‌حش نه‌بوو، و وى فه‌حشاتى نه‌ دكر ژى، و وى گۆت: باشێ هه‌وه‌ ئه‌وه‌ یێ ئه‌خلاقێ وى چێتر بت.', NULL, true),
  (446, 'كەنییا پێغەمبەرى گڕنژین بوو', 'عَنْ عَائِشَةَ -رَضِيَ الله عَنْهَا- قَالَتْ: مَا رَأَيْتُ النَّبِيَّﷺ مُسْتَجْمِعًا قَطُّ ضَاحِكًا حَتَّى أَرَى مِنْهُ لَهَوَاتِهِ، إِنَّمَا كَانَ يَتَبَسَّمُ.', 'عائیشا -خودێ ژێ رازى بت- دبێژت: من پێغه‌مبه‌ر -سلاڤ لێ بن- قه‌ت نه‌دیت كه‌نییه‌كا وه‌سا كربت حه‌تا كو ئه‌ز پاشییا ده‌ڤێ وى ببینم، هه‌ما ب تنێ ئه‌و دگڕنژى.', NULL, true),
  (456, 'باشییا دانێ و خرابییا دەستگرتنێ', 'عَنْ أَبِي هُرَيْرَةَ رضي الله عنه أَنَّ النَّبِيَّﷺ قَالَ: «مَا مِنْ يَوْمٍ يُصْبِحُ الْعِبَادُ فِيهِ إِلَّا مَلَكَانِ يَنْزِلَانِ فَيَقُولُ أَحَدُهُمَا: اللهمَّ أَعْطِ مُنْفِقًا خَلَفًا، وَيَقُولُ الْآخَرُ: اللهمَّ أَعْطِ مُمْسِكًا تَلَفًا».', 'ئه‌بوو هوره‌یره‌ -خودێ ژێ رازى بت- دبێژت: پێغه‌مبه‌رى -سلاڤ لێ بن- گۆت: هه‌ر ڕۆژه‌كا ل به‌نییان دبته‌ سپێده‌ دو ملیاكه‌ت دئێنه‌ خوارێ، ئێك ژ وان دبێژت: ئه‌ى خودا هه‌چییێ بده‌ت تو بۆ به‌ده‌ل ڤه‌كه‌ى، و یێ دى دبێژت: هه‌چییێ نه‌ده‌ت كو لێ بته‌لێفى.', NULL, true),
  (466, 'خێرا خەزنەدارێ ئەمین', 'عَنْ أَبِي مُوسَى رضي الله عنه عَنِ النَّبِيِّﷺ قَالَ: «إِنَّ الخَازِنَ المُسْلِمَ الْأَمِينَ الَّذِي يُنْفِذُ -وَرُبَّمَا قَالَ يُعْطِي- مَا أُمِرَ بِهِ، فَيُعْطِيهِ كَامِلًا مُوَفَّرًا، طَيِّبَةً بِهِ نَفْسُهُ، فَيَدْفَعُهُ إِلَى الَّذِي أُمِرَ لَهُ بِهِ، أَحَدُ الْمُتَصَدِّقَيْنِ».', 'ئه‌بوو مووسا -خودێ ژێ رازى بت- دبێژت: پێغه‌مبه‌رى -سلاڤ لێ بن- گۆت: خه‌زنه‌دارێ موسلمانێ ئه‌مین ئه‌وێ وى تشتى ب تمامى ب جهـ دئینت -یان گۆت: دده‌ت- یێ فه‌رمان پێ لێ هاتییه‌كرن، و ب دله‌كێ خۆش بده‌ته‌ وى یێ فه‌رمان پێ لێ هاتییه‌كرن، ئه‌و ئێك ژ خێركه‌رانه‌.', NULL, true),
  (476, 'دەمێ ژن خوارنێ ژ مالا خۆ ددەت', 'عَنْ عَائِشَةَ -رضي الله عنها- قَالَتْ: قَالَ رَسُولُ اللهﷺ : «إِذَا أَنْفَقَتِ المَرْأَةُ مِنْ طَعَامِ بَيْتِهَا غَيْرَ مُفْسِدَةٍ، كَانَ لَهَا أَجْرُهَا بِمَا أَنْفَقَتْ، وَلِزَوْجِهَا أَجْرُهُ بِمَا كَسَبَ، وَلِلْخَازِنِ مِثْلُ ذَلِكَ، لَا يَنْقُصُ بَعْضُهُمْ أَجْرَ بَعْضٍ شَيْئًا».', 'عائیشا -خودێ ژێ رازى بت- دبێژت: پێغه‌مبه‌رى -سلاڤ لێ بن- گۆت: ئه‌گه‌ر ژن ژ خوارنا مالا خۆ بێى یا خرابكار بت خه‌رج بكه‌ت، خێرا وى تشتێ وێ خه‌رجكرى بۆ وێ هه‌یه‌، و خێر بۆ مێرێ وێ ژ به‌ر كه‌سبا وى هه‌یه‌، و بۆ خه‌زنه‌دارى ژى وه‌سا هه‌یه‌، هنده‌ك ژ وان خێرا هنده‌كان كێم ناكه‌ن.', NULL, true),
  (486, 'خێرا وى یێ بیژنێ و هەژارى ب خودان دكەت', 'عَنْ أَبِي هُرَيْرَةَ رضي الله عنه عَنِ النَّبِيِّﷺ قَالَ: «السَّاعِي عَلَى الْأَرْمَلَةِ وَالْمِسْكِينِ، كَالمُجَاهِدِ فِي سَبِيلِ الله، أوالْقَائِمِ اللیلَ، الصَّائِمِ النَهَارَ».', 'ئه‌بوو هوره‌یره‌ -خودێ ژێ رازى بت- دبێژت: پێغه‌مبه‌رى -سلاڤ لێ بن- گۆت: ئه‌وێ ب كارێ بیژن و هه‌ژارى ڕادبت، وه‌كى وییه‌ یێ جیهادێ د ڕێكا خودێ دا دكه‌ت، یان یێ ب شه‌ڤێ عیباده‌تى دكه‌ت، و ب ڕۆژێ یێ ب ڕۆژى.', NULL, true);
INSERT INTO gencine_hadiths (sort_order, title, ar, ku, source, active) VALUES
  (496, 'موسلمان دڤێت هەر خێرێ بكەت', 'عَنْ أَبِي موسى الأشعري رضي الله عنه عَنِ النَّبِيِّﷺ قَالَ: «عَلَى كُلِّ مُسْلِمٍ صَدَقَةٌ» قِيلَ: أَرَأَيْتَ إِنْ لَمْ يَجِدْ؟ قَالَ: «يَعْتَمِلُ بِيَدَيْهِ فَيَنْفَعُ نَفْسَهُ وَيَتَصَدَّقُ» قَالَ: قِيلَ: أَرَأَيْتَ إِنْ لَمْ يَسْتَطِعْ؟ قَالَ: «يُعِينُ ذَا الحَاجَةِ المَلْهُوفَ» قَالَ: قِيلَ لَهُ: أَرَأَيْتَ إِنْ لَمْ يَسْتَطِعْ؟ قَالَ: «يَأْمُرُ بِالمَعْرُوفِ أَوِ الخَيْرِ» قَالَ: أَرَأَيْتَ إِنْ لَمْ يَفْعَلْ؟ قَالَ: «يُمْسِكُ عَنِ الشَّرِّ، فَإِنَّهَا صَدَقَةٌ».', 'ئه‌بوو مووسایێ ئه‌شعه‌رى‌ -خودێ ژێ رازى بت- دبێژت: پێغه‌مبه‌رى -سلاڤ لێ بن- گۆت: ل سه‌ر هه‌ر موسلمانه‌كى خێره‌ك هه‌یه‌. هاته‌ گۆتن: پا ئه‌گه‌ر وى چو نه‌بت؟ گۆت: دێ كارى ب ده‌ستێ خۆ كه‌ت، ڤێجا دێ مفایى گه‌هینته‌ خۆ و خێرێ كه‌ت. هاته‌ گۆتن: پا ئه‌گه‌ر نه‌شێت وه‌ بكه‌ت؟ گۆت: دێ هاریكارییا كه‌سێ پێتڤى و بێ ڕێ كه‌ت. هاته‌ گۆتن: پا ئه‌گه‌ر نه‌شیا وه‌ بكه‌ت؟ گۆت: دێ فه‌رمانێ ب باشییێ یان خێرێ كه‌ت. گۆت: پا ئه‌گه‌ر وى وه‌ نه‌كر؟ گۆت: خرابییێ ناكه‌ت، ئه‌و خێره‌.', NULL, true),
  (506, 'باشترین خێر', 'عن حَكِيمِ بْنِ حِزَامٍ رضي الله عنه أَنَّ رَسُولَ اللهﷺ قَالَ: «أَفْضَلُ الصَّدَقَةِ، أَوْ خَيْرُ الصَّدَقَةِ عَنْ ظَهْرِ غِنًى، وَالْيَدُ الْعُلْيَا خَيْرٌ مِنَ الْيَدِ السُّفْلَى، وَابْدَأْ بِمَنْ تَعُولُ».', 'حه‌كیمێ كوڕێ حزامى -خودێ ژێ رازى بت- دبێژت: پێغه‌مبه‌رى -سلاڤ لێ بن- گۆت: چێترین خێر، یان باشترین خێر ئه‌وه‌ یا ژ ده‌وله‌مه‌ندییێ بت، و ده‌ستێ بلندتر باشتره‌ ژ ده‌ستێ نزمتر، و تو ژ وى ده‌ست پێ بكه‌ یێ تو وى ب خودان دكه‌ى.', NULL, true),
  (516, 'دەولەمەندییا دورست', 'عَنْ أَبِي هُرَيْرَةَ رضي الله عنه قَالَ: قَالَ رَسُولُ اللهﷺ : «لَيْسَ الْغِنَى عَنْ كَثْرَةِ الْعَرَضِ، وَلَكِنَّ الْغِنَى غِنَى النَّفْسِ».', 'ئه‌بوو هوره‌یره‌ -خودێ ژێ رازى بت- دبێژت: پێغه‌مبه‌رى -سلاڤ لێ بن- گۆت: ده‌وله‌مه‌ندى نه‌ ب هه‌بوونا گه‌له‌ك په‌رتالییه‌، به‌لێ ده‌وله‌مه‌ندى ده‌وله‌مه‌ندییا نه‌فسێیه‌.', NULL, true),
  (526, 'هەژارێ دورست كییە؟', 'عن أَبي هُرَيْرَةَ رضي الله عنه قَالَ: قَالَ النَّبِيُّﷺ : «لَيْسَ الْمِسْكِينُ الَّذِي يَطُوفُ عَلَى النَّاسِ تَرُدُّهُ اللُّقْمَةُ وَاللُّقْمَتَانِ، وَالتَّمْرَةُ وَالتَّمْرَتَانِ، وَلَكِنِ الْمِسْكِينُ الَّذِي لا يَجِدُ غِنًى يُغْنِيهِ، وَلا يُفْطَنُ بِهِ، فَيُتَصَدَّقُ عَلَيْهِ، وَلا يَقُومُ فَيَسْأَلُ النَّاسَ».', 'ئه‌بوو هوره‌یره‌ -خودێ ژێ رازى بت- دبێژت: پێغه‌مبه‌رى -سلاڤ لێ بن- گۆت: هه‌ژار ئه‌و نینه‌ یێ ل سه‌ر خه‌لكى دگه‌ڕیێت ڤێجا پارییه‌ك یان دو، و قه‌سپه‌ك یان دو وى دزڤڕینت، به‌لێ هه‌ژار ئه‌وه‌ یێ ده‌وله‌مه‌ندییه‌ك ب ده‌ست وى نه‌كه‌ڤت وى بێ منه‌ت بكه‌ت، و كه‌سێ هاى ژێ نینه‌ خێرێ د گه‌ل بكه‌ت، و ئه‌و خواستنێ ژ مرۆڤان ناكه‌ت.', NULL, true),
  (536, 'خواستن كارەكێ باش نینه', 'عن أَبي هُرَيْرَةَ رضي الله عنه عن النَّبِيّﷺ قَالَ: «لأنْ يَحْتَطِبَ أَحَدُكُمْ حُزْمَةً عَلَى ظَهْرِهِ، خَيْرٌ لَهُ مِنْ أَنْ يَسْأَلَ أَحَدًا، فَيُعْطِيَهُ أَوْ يَمْنَعَهُ».', 'ئه‌بوو هوره‌یره‌ -خودێ ژێ رازى بت- دبێژت: پێغه‌مبه‌رى -سلاڤ لێ بن- گۆت: ئه‌گه‌ر ئێك ژ هه‌وه‌ باره‌كێ داران ل سه‌ر پشتا خۆ هلگرت، بۆ وى چێتره‌ كو خواستنێ ژ ئێكى بكه‌ت، ڤێجا كانێ ئه‌و دێ ده‌تێ یان نه‌.', NULL, true),
  (546, 'ئەنجامێ خواستنێ یێ خراب', 'عَنْ عَبْدِ الله بْنِ عمر رضي الله عنه أَنَّ النَّبِيَّﷺ، قَالَ: «لاَ تَزَالُ المَسْأَلَةُ بِأَحَدِكُمْ حَتَّى يَلْقَى الله، وَلَيْسَ فِي وَجْهِهِ مُزْعَةُ لحْمٍ».', 'عه‌بدللاهێ كوڕێ عومه‌رى -خودێ ژ هه‌ردویان رازى بت- دبێژت: پێغه‌مبه‌رى -سلاڤ لێ بن- گۆت: خواستن دێ مینته‌ ب ئێك ژ هه‌وه‌ ڤه‌ حه‌تا ئه‌و دچته‌ نك خودێ و پشكه‌كا گۆشتى ب ڕوییێ وى ڤه‌ نه‌.', NULL, true),
  (556, 'كارى ل بەر خەلكى ب ساناهى بكەن', 'عن أَنَسِ بْنِ مَالِكٍ رضي الله عنه عنْ رَسُولِ اللهﷺ قَالَ: «يَسِّرُوا وَلاَ تُعَسِّرُوا، وَبَشِّروا وَلاَ تُنَفِّرُوا».', 'ئه‌نه‌سێ كوڕێ مالكى -خودێ ژێ رازى بت- دبێژت: پێغه‌مبه‌رى -سلاڤ لێ بن- گۆت: ل به‌ر خه‌لكى ب ساناهى بێخن و ب زه‌حمه‌ت نه‌كه‌ن، و مزگینییێ بگه‌هینن و خه‌لكى ژ خۆ نه‌ڕه‌ڤینن.', NULL, true),
  (566, 'كیژ مرۆڤ چێترە؟', 'عَنْ أَبِي سَعِيدٍ رضي الله عنه قَالَ: قَالَ رَجُلٌ: أَيُّ النَّاسِ أَفْضَلُ يَا رَسُولَ الله؟ قَالَ: «مُؤْمِنٌ يُجَاهِدُ بِنَفْسِهِ وَمَالِهِ فِي سَبِيلِ الله» قَالَ: ثُمَّ مَنْ؟ قَالَ: «ثُمَّ رَجُلٌ مُعْتَزِلٌ فِي شِعْبٍ مِنَ الشِّعَابِ يَعْبُدُ رَبَّهُ، وَيَدَعُ النَّاسَ مِنْ شَرِّهِ».', 'ئه‌بوو سه‌عید -خودێ ژێ رازى بت- دبێژت: زه‌لامه‌كى گۆت: كیژ مرۆڤ چێتره‌ ئه‌ى پێغه‌مبه‌رێ خودێ؟ وى گۆت: خودان باوه‌ره‌كێ جیهادێ ب نه‌فسا خۆ و مالێ خۆ د ڕێكا خودێ دا دكه‌ت. گۆت: پاشى كى؟ وى گۆت: پاشى زه‌لامه‌كێ خۆ د گه‌لییان دا ڤه‌ده‌ركه‌ت، په‌ڕستنا خودایێ خۆ بكه‌ت، و به‌لا خۆ ژ خه‌لكى ڤه‌كه‌ت.', NULL, true),
  (576, 'سێ كەسێن خودێ ل قیامەتێ د گەل نائاخڤت', 'عَنْ أَبِي هُرَيْرَةَ رضي الله عنه قَالَ: قَالَ رَسُولُ اللهﷺ : «ثَلاَثٌ لاَ يُكَلِّمُهُمُ الله يَوْمَ الْقِيَامَةِ، وَلاَ يَنْظُرُ إِلَيْهِمْ، وَلاَ يُزَكِّيهِمْ وَلَهُمْ عَذَابٌ أَلِيمٌ: رَجُلٌ عَلَى فَضْلِ مَاءٍ بِالْفَلاَةِ يَمْنَعُهُ مِنَ ابْنِ السَّبِيلِ، وَرَجُلٌ بَايَعَ رَجُلاً بِسِلْعَةٍ بَعْدَ الْعَصْرِ فَحَلَفَ لَهُ بِالله لأَخَذَهَا بِكَذَا وَكَذَا فَصَدَّقَهُ وَهُوَ عَلَى غَيْرِ ذَلِكَ، وَرَجُلٌ بَايَعَ إِمَامًا لاَ يُبَايِعُهُ إِلاَّ لِدُنْيَا فَإِنْ أَعْطَاهُ مِنْهَا وَفَى، وَإِنْ لَمْ يُعْطِهِ مِنْهَا لَمْ يَفِ».', 'ئه‌بوو هوره‌یره‌ -خودێ ژێ رازى بت- دبێژت: پێغه‌مبه‌رى -سلاڤ لێ بن- گۆت: سێ كه‌س هه‌نه‌ خودێ ڕۆژا قیامه‌تێ د گه‌ل وان نائاخڤت، و به‌رێ خۆ ناده‌تێ، و عه‌زابه‌كا ب ئێش بۆ وان هه‌یه‌: زه‌لامه‌كێ ئاڤه‌كا زێده‌ ل به‌ڕییێ د گه‌ل دا بت، و ئه‌و وێ نه‌ده‌ته‌ ڕێڤنگى، و زه‌لامه‌كێ پشتى ئێڤارى په‌رتاله‌ك فرۆتییه‌ زه‌لامه‌كى و سویند ب خودێ خوارى كو وى ئه‌و ب هندێ و هندێ وه‌رگرتییه‌ ڤێجا باوه‌رییا وى پێ بێت و ئه‌و ب خۆ وه‌سا نه‌بت، و زه‌لامه‌كێ ب دنیایێ به‌یعه‌ دایه‌ ئیمامه‌كى، ڤێجا ئه‌گه‌ر ئه‌و تشته‌كى ژ دنیایێ بده‌تێ ئه‌و د گه‌ل وى یێ ب وه‌فا بت، و ئه‌گه‌ر چو نه‌دایێ یێ ب وه‌فا نه‌بت.', NULL, true),
  (586, 'هندەك باوەرییێن نەدورست', 'عن أَبي هُرَيْرَةَ رضي الله عنه قَالَ: قال رَسُول اللهﷺ : «لاَ عَدْوَى وَلاَ طِيَرَةَ وَلاَ هَامَةَ وَلاَ صَفَرَ».', 'ئه‌بوو هوره‌یره‌ -خودێ ژێ رازى بت- دبێژت: پێغه‌مبه‌رى -سلاڤ لێ بن- گۆت: چو ڤه‌گرتن، و بێ ئیفله‌حى، ب طه‌یران و ئێشا زكى نینه‌.', NULL, true),
  (596, 'مرۆڤ هەمى بەرپڕسن', 'عن عَبْدِ الله بْنِ عُمَرَ رضي الله عنه يَقُولُ: سَمِعْتُ رَسُولَ اللهﷺ يَقُولُ: «كُلُّكُمْ رَاعٍ وَكُلُّكُمْ مَسْؤُولٌ عَنْ رَعِيَّتِهِ، الإِمَامُ رَاعٍ وَمَسْؤُولٌ عَنْ رَعِيَّتِهِ، وَالرَّجُلُ رَاعٍ فِي أَهْلِهِ وَهْوَ مَسْؤُولٌ عَنْ رَعِيَّتِهِ، وَالْمَرْأَةُ رَاعِيَةٌ فِي بَيْتِ زَوْجِهَا وَمَسْؤُولَةٌ عَنْ رَعِيَّتِهَا، وَالخَادِمُ رَاعٍ فِي مَالِ سَيِّدِهِ وَمَسْؤُولٌ عَنْ رَعِيَّتِهِ، وَالرَّجُلُ رَاعٍ فِي مَالِ أَبِيهِ وَمَسْؤُولٌ عَنْ رَعِيَّتِهِ، وَكُلُّكُمْ رَاعٍ وَمَسْؤُولٌ عَنْ رَعِيَّتِهِ».', 'عه‌بدللاهێ كوڕێ عومه‌رى -خودێ ژ هه‌ردویان رازى بت- دبێژت: پێغه‌مبه‌رى -سلاڤ لێ بن- گۆت: هوین هه‌مى شڤانن و هوین هه‌مى ژ شڤانییا خۆ به‌رپڕسن، و زه‌لام د مالا خۆ دا شڤانه‌ و ئه‌و ژ شڤانییا خۆ به‌رپڕسه‌، و ژن د مالا زه‌لامێ خۆ دا شڤانه‌ و ئه‌و ژ شڤانییا خۆ به‌رپڕسه‌، و خزمه‌تكار د مالێ باخویێ خۆ دا شڤانه‌ و ئه‌و ژ شڤانییا خۆ به‌رپڕسه‌، و زه‌لام د مالێ بابێ خۆ دا شڤانه‌ و ئه‌و ژ شڤانییا خۆ به‌رپڕسه‌، و هوین هه‌مى شڤانن و ژ شڤانییا خۆ به‌رپڕسن.', NULL, true),
  (606, 'گرنگییا ژنئینان و شویكرنێ', 'عَنْ عَبْدِ الله بن مسعود رضي الله عنه قَالَ: قَالَ رَسُولُ اللهﷺ : «يَا مَعْشَرَ الشَّبَابِ، مَنِ اسْتَطَاعَ مِنْكُمُ الْبَاءَةَ فَلْيَتَزَوَّجْ، فَإِنَّهُ أَغَضُّ لِلْبَصَرِ، وَأَحْصَنُ لِلْفَرْجِ، وَمَنْ لَمْ يَسْتَطِعْ فَعَلَيْهِ بِالصَّوْمِ، فَإِنَّهُ لَهُ وِجَاءٌ».', 'عه‌بدللاهێ كوڕێ مه‌سعوودى -خودێ ژێ رازى بت- دبێژت: پێغه‌مبه‌رى -سلاڤ لێ بن- گۆت: گه‌لى جحێلان هه‌چییێ ژ هه‌وه‌ شیا ژنێ بینت بلا بینت، ئه‌و پتر چاڤى دگرت و نامویسێ دپارێزت، و هه‌چییێ نه‌شێت بلا ڕۆژییێ بگرت، ئه‌و بۆ وى په‌رژانه‌.', NULL, true),
  (616, 'ئەگەرێن مارەكرنا ژنێ', 'عَنْ أَبِي هُرَيْرَةَ رضي الله عنه عَنِ النَّبِيِّﷺ قَالَ: «تُنْكَحُ المَرْأَةُ لِأَرْبَعٍ: لِمَالِهَا، وَلِحَسَبِهَا، وَلِجَمَالِهَا، وَلِدِينِهَا، فَاظْفَرْ بِذَاتِ الدِّينِ تَرِبَتْ يَدَاكَ».', 'ئه‌بوو هوره‌یره‌ -خودێ ژێ رازى بت- دبێژت: پێغه‌مبه‌رى -سلاڤ لێ بن- گۆت: ژن ژ به‌ر چار تشتان دئێته‌ ماره‌كرن: ژ به‌ر مالێ وێ، و مالباتا وێ، و جوانییا وێ، و دینێ وێ، ڤێجا تو یا خودان دین ب ده‌ست خۆ بێخه‌‌.', NULL, true),
  (626, 'وه ئێمانەت ژن', 'عَنْ أَبِي هُرَيْرَةَ رضي الله عنه عَنِ النَّبِيِّﷺ قَالَ: «مَنْ كَانَ يُؤْمِنُ بِالله وَالْيَوْمِ الآخِرِ فَلا يُؤْذِى جَارَهُ، وَاسْتَوْصُوا بِالنِّسَاءِ خَيْرًا، فَإِنَّهُنَّ خُلِقْنَ مِنْ ضِلَعٍ، وَإِنَّ أَعْوَجَ شَىْءٍ فِى الضِّلَعِ أَعْلاهُ، فَإِنْ ذَهَبْتَ تُقِيمُهُ كَسَرْتَهُ، وَإِنْ تَرَكْتَهُ لَمْ يَزَلْ أَعْوَجَ، فَاسْتَوْصُوا بِالنِّسَاءِ خَيْرًا».', 'ئه‌بوو هوره‌یره‌ -خودێ ژێ رازى بت- دبێژت: پێغه‌مبه‌رى -سلاڤ لێ بن- گۆت: هه‌چییێ باوه‌رى ب خودێ و ڕۆژا دووماهییێ هه‌بت بلا نه‌خۆشییێ نه‌گه‌هینته‌ جیرانێ خۆ، و وه‌ ئێمانه‌ت ژن د گه‌ل دباش بن، چونكى ئه‌و یێ ژ په‌ڕاسییێ هاتینه‌ ئافراندن، و جهێ ژ هه‌مییێ خوارتر د په‌ڕاسییێ دا سه‌رێ وییه‌، و ئه‌گه‌ر تو بچى ڕاست كه‌ى دێ شكێنى و ئه‌گه‌ر تو بهێلى دێ مینت خوار، ڤێجا د گه‌ل ژنان دباش بن.', NULL, true),
  (636, 'گونەها وێ ژنا د بەرسڤا مێرێ خۆ نەچت', 'عَنْ أَبِي هُرَيْرَةَ رضي الله عنه قَالَ: قَالَ رَسُولُ اللهﷺ : «إِذَا دَعَا الرَّجُلُ امْرَأَتَهُ إِلَى فِرَاشِهِ، فَلَمْ تَأْتِهِ، فَبَاتَ غَضْبَانَ عَلَيْهَا، لَعَنَتْهَا المَلَائِكَةُ حَتَّى تُصْبِحَ».', 'ئه‌بوو هوره‌یره‌ -خودێ ژێ رازى بت- دبێژت: پێغه‌مبه‌رى -سلاڤ لێ بن- گۆت: ئه‌گه‌ر زه‌لامى ژن بۆ نڤینا خۆ داخوازكر و ئه‌و د به‌رسڤا وى نه‌چوو، و ئه‌و بنڤت و یێ ژێ عێجز، حه‌تا سپێدێ ملیاكه‌ت له‌عنه‌تان ل وێ دكه‌ن.', NULL, true),
  (646, 'كارێ شەیطانى د گەل مرۆڤى', 'عَنْ أم المؤمنین صَفِيَّةَ بِنْتِ حُيَيٍّ -رضي الله عنها- قَالَتْ: كَانَ النَّبِيُّﷺ مُعْتَكِفًا، فَأَتَيْتُهُ أَزُورُهُ لَيْلًا، فَحَدَّثْتُهُ، ثُمَّ قُمْتُ لِأَنْقَلِبَ، فَقَامَ مَعِيَ لِيَقْلِبَنِي، فَمَرَّ رَجُلَانِ مِنَ الْأَنْصَارِ، فَلَمَّا رَأَيَا النَّبِيَّﷺ أَسْرَعَا، فَقَالَ النَّبِيُّﷺ : «عَلَى رِسْلِكُمَا، إِنَّهَا صَفِيَّةُ بِنْتُ حُيَيٍّ» فَقَالَا: سُبْحَانَ الله يَا رَسُولَ الله، قَالَ: «إِنَّ الشَّيْطَانَ يَجْرِي مِنَ الْإِنْسَانِ مَجْرَى الدَّمِ، وَإِنِّي خَشِيتُ أَنْ يَقْذِفَ فِي قُلُوبِكُمَا شَرًّا أَوْ قَالَ شَيْئًا».', 'ده‌یكا خودان باوه‌ران صه‌فییایا كچا حویه‌یى -خودێ ژێ رازى بت- دبێژت: پێغه‌مبه‌ر -سلاڤ لێ بن- د ئعتكافێ دا بوو، شه‌ڤه‌كێ ئه‌ز هاتم سه‌را بده‌م، ئه‌ز د گه‌ل ئاخفتم، پاشى ئه‌ز ڕابووم دا بزڤڕمه‌ڤه‌، ئه‌و ژى ڕابوو دا من بده‌ته‌ ڕێ، دو زه‌لامێن ئه‌نصارى بۆرین، و گاڤا وان پێغه‌مبه‌ر -سلاڤ لێ بن- دیتى وان پییێن خۆ سڤك كرن، پێغه‌مبه‌رى -سلاڤ لێ بن- گۆت: له‌زێ نه‌كه‌ن، ئه‌ڤه‌ صه‌فییایا كچا حویه‌یه‌. وان گۆت: (سبحان الله) ئه‌ى پێغه‌مبه‌رێ خودێ! وى گۆت: هندى شه‌یطانه‌ د جهێ خوینێ ڕا ژ مرۆڤى دگه‌ڕیێت، و ئه‌ز ترسیام ئه‌و خرابییه‌كێ یان گۆت تشته‌كى بهاڤێته‌ دلێن هه‌وه‌.', NULL, true),
  (656, 'وەفادارییا پێغەمبەرى د گەل خەدیجایێ', 'عَنْ عَائِشَةَ -رَضِيَ الله عَنْهَا- قَالَتْ: مَا غِرْتُ عَلَى أَحَدٍ مِنْ نِسَاءِ النَّبِيِّﷺ مَا غِرْتُ عَلَى خَدِيجَةَ، وَمَا رَأَيْتُهَا، وَلَكِنْ كَانَ النَّبِيُّﷺ يُكْثِرُ ذِكْرَهَا، وَرُبَّمَا ذَبَحَ الشَّاةَ ثُمَّ يُقَطِّعُهَا أَعْضَاءً ثُمَّ يَبْعَثُهَا فِي صَدَائِقِ خَدِيجَةَ، فَرُبَّمَا قُلْتُ لَهُ: كَأَنَّهُ لَمْ يَكُنْ فِي الدُّنْيَا امْرَأَةٌ إِلاَّ خَدِيجَةُ! فَيَقُولُ: «إِنَّهَا كَانَتْ وَكَانَتْ، وَكَانَ لِي مِنْهَا وَلَدٌ».', 'ده‌یكا خودان باوه‌ران عائیشا -خودێ ژێ رازى بت- دبێژت: غیره‌ت بۆ من ل سه‌ر ئێك ژ ژنكێن پێغه‌مبه‌رى -سلاڤ لێ بن- چێ نه‌بوویه‌ وه‌كى كو غیره‌ت بۆ من ل سه‌ر خه‌دیجایێ چێبووى، و من ئه‌و نه‌دیتبوو، به‌لێ پێغه‌مبه‌رى -سلاڤ لێ بن- گه‌له‌ك به‌حسێ وێ دكر، و ده‌مێ وى په‌زه‌ك ڤه‌كوشتبا، وى ئه‌و پارچه‌ پارچه‌ دكر، و ل سه‌ر هه‌ڤالێن خه‌دیجایێ لێكڤه‌دكر، و جاره‌كێ من گۆتێ: هه‌ر وه‌كى چو ژن ژ بلى خه‌دیجایێ د دنیایێ دا نه‌بوون؟! وى گۆت: ئه‌و یا هۆسا بوو و هۆسا بوو.. و من عه‌یال ژ وێ هه‌بوو.', NULL, true),
  (666, 'زڤڕین ژ وەغەرێ ل ئێڤارییان', 'عَنْ جَابِرِ بْنِ عَبْدِ الله رضي الله عنه قَالَ: كُنَّا مَعَ رَسُولِ اللهﷺ فِي غَزَاةٍ، فَلَمَّا قَدِمْنَا المَدِينَةَ، ذَهَبْنَا لِنَدْخُلَ، فَقَالَ: «أَمْهِلُوا حَتَّى نَدْخُلَ لَيْلًا -أَيْ عِشَاءً- كَيْ تَمْتَشِطَ الشَّعِثَةُ، وَتَسْتَحِدَّ المُغِيبَةُ».', 'جابرێ كوڕێ عه‌بدللاهى -خودێ ژێ رازى بت- دبێژت: ئه‌م د گه‌ل پێغه‌مبه‌رى -سلاڤ لێ بن- د غه‌زایه‌كێ دا بووین، و ده‌مێ ئه‌م هاتینه‌ مه‌دینێ، ئه‌م چووین دا قه‌ستا مالێن خۆ بكه‌ین، ئینا پێغه‌مبه‌رى -سلاڤ لێ بن- گۆت: له‌زێ نه‌كه‌ن حه‌تا ل مه‌ دبته‌ ئێڤار؛ دا ژن سه‌رێن خۆ شه‌ بكه‌ن، و خۆ پاقژ بكه‌ن.', NULL, true),
  (676, 'نیهارا ژنێ ل سەر مرى', 'عَنْ زَيْنَبَ بِنْتِ أَبِي سَلَمَةَ -رضي الله عنها- قَالَتْ: دَخَلْتُ عَلَى أُمِّ حَبِيبَةَ زَوْجِ النَّبِيِّﷺ حِينَ تُوُفِّيَ أَبُوهَا أَبو سُفْيَانَ، فَدَعَتْ أُمُّ حَبِيبَةَ بِطِيبٍ فِيهِ صُفْرَةٌ خَلُوقٌ أَوْ غَيْرُهُ فَدَهَنَتْ مِنْهُ جَارِيَةً، ثُمَّ مَسَّتْ بِعَارِضَيْهَا، ثُمَّ قَالَتْ: وَالله مَا لِي بِالطِّيبِ مِنْ حَاجَةٍ، غَيْرَ أَنِّي سَمِعْتُ رَسُولَ اللهﷺ يَقُولُ عَلَى الْمِنْبَرِ: «لَا يَحِلُّ لِامْرَأَةٍ تُؤْمِنُ بِالله وَالْيَوْمِ الْآخِرِ تُحِدُّ عَلَى مَيِّتٍ فَوْقَ ثَلَاثٍ، إِلَّا عَلَى زَوْجٍ أَرْبَعَةَ أَشْهُرٍ وَعَشْرًا».', 'زه‌ینه‌با كچا ئه‌بوو سه‌له‌مه‌یى -خودێ ژێ رازى بت- دبێژت: ئه‌ز چوومه‌ نك كابانییا پێغه‌مبه‌رى -سلاڤ لێ بن- ئه‌م حه‌بیبه‌یێ ده‌مێ بابێ وێ ئه‌بوو سوفیان مرى، وێ هنده‌ك بێنا خۆش داخوازكر، و هنده‌ك ژێ ل كچه‌كێ كر پاشى ده‌ستێن خۆ د جێنیكێن خۆ دان و گۆت: ب خودێ من چو هه‌وجه‌یى ب بێنا خۆش نینه‌، به‌لێ من گوهـ ل پێغه‌مبه‌رى -سلاڤ لێ بن- بوویه‌ وى ل سه‌ر مینه‌به‌رێ دگۆت: حه‌لال نینه‌ بۆ ژنه‌كا باوه‌رى ب خودێ و ڕۆژا دووماهییێ هه‌ى كو ئه‌و پتر ژ سێ ڕۆژان نیهارێ ل سه‌ر مرییه‌كى بكه‌ت، ل سه‌ر زه‌لامێ وێ تێ نه‌بت، ئه‌و چار هه‌یڤ و ده‌هـ ڕۆژان بۆ وى دێ وێ چه‌ندێ كه‌ت.', NULL, true),
  (686, 'خویشك و براینییا شیرى', 'عَنِ ابْنِ عَبَّاسٍ رضي الله عنه أَنَّ النَّبِيَّﷺ أُرِيدَ عَلَى ابْنَةِ حَمْزَةَ، فَقَالَ: «إِنَّهَا لَا تَحِلُّ لِي، إِنَّهَا ابْنَةُ أَخِي مِنَ الرَّضَاعَةِ، وَيَحْرُمُ مِنَ الرَّضَاعَةِ مَا يَحْرُمُ مِنَ الرَّحِمِ».', 'عه‌بدللاهێ كوڕێ عه‌بباسى -خودێ ژ هه‌ردویان رازى بت- دبێژت: بۆ پێغه‌مبه‌رى -سلاڤ لێ بن- هاته‌ حه‌زكرن كو ئه‌و كچا حه‌مزه‌یى ماره‌ بكه‌ت، وى گۆت: ئه‌و بۆ من یا حه‌لال نینه‌، ئه‌و كچا برایێ من یێ شیرییه‌، و ئه‌و ب شیرى حه‌رام دبت یا ب نه‌سه‌بێ حه‌رام دبت.', NULL, true);
INSERT INTO gencine_hadiths (sort_order, title, ar, ku, source, active) VALUES
  (696, 'خۆشتڤیترین كار ل نك خودێ', 'عن عَبْدِ الله بن مسعود رضي الله عنه قَالَ: سَأَلْتُ رَسُولَ اللهﷺ : أَيُّ الْأَعْمَالِ أَحَبُّ إِلَى الله؟ قَالَ: «الصَّلَاةُ عَلَى وَقْتِهَا» قُلْتُ: ثُمَّ أَيٌّ؟ قَالَ: «ثُمَّ بِرُّ الْوَالِدَيْنِ» قُلْتُ: ثُمَّ أَيٌّ؟ قَالَ: «ثُمَّ الْجِهَادُ فِي سَبِيلِ الله».', 'عه‌بدللاهێ كوڕێ مه‌سعوودى -خودێ ژێ رازى بت- دبێژت: من پسیار ژ پێغه‌مبه‌رى -سلاڤ لێ بن- كر كیژ كار خۆشتڤیترین كارن ل نك خودێ؟ وى گۆت: نڤێژ ل ده‌مێ وێ، من گۆت: پاشى چ؟ وى گۆت: پاشى قه‌نجییا د گه‌ل ده‌یبابان. من گۆتێ: پاشى چ؟ وى گۆت: پاشى جیهادا د ڕێكا خودێ دا.', NULL, true),
  (706, 'تشتێ خودێ ل سەر هەوه حەرامكرى و تشتێ وى بۆ هەوه نەڤیاى', 'عَنِ المُغِيرَةِ بْنِ شُعْبَةَ رضي الله عنه عَنْ رَسُولِ اللهﷺ قَالَ: «إِنَّ اللهَ عَزَّ وَجَلَّ حَرَّمَ عَلَيْكُمْ: عُقُوقَ الْأُمَّهَاتِ، وَوَأْدَ الْبَنَاتِ، وَمَنْعًا وَهَاتِ، وَكَرِهَ لَكُمْ ثَلَاثًا: قِيلَ وَقَالَ، وَكَثْرَةَ السُّؤَالِ، وَإِضَاعَةَ المَالِ».', 'موغیره‌یێ كوڕێ شوعبه‌یى -خودێ ژێ رازى بت- دبێژت: پێغه‌مبه‌رى -سلاڤ لێ بن- گۆت: هندى خودایێ پاك و بلنده‌ هێلانا دلێ ده‌یكان، و ڤه‌شارتنا كچان ب ساخى و گرتنا مالى و به‌س كۆمكرن ل سه‌ر هه‌وه‌ حه‌رامكرییه‌، و وى سێ تشت بۆ هه‌وه‌ نه‌ڤیاینه‌: گۆتۆیى گۆت، و گه‌له‌ك خواستن، و زه‌عێكرنا مالى.', NULL, true),
  (716, 'كی هێژاتره بۆ هەڤالینییا من؟', 'عَنْ أَبِي هُرَيْرَةَ رضي الله عنه قَالَ: جَاءَ رَجُلٌ إِلَى رَسُولِ اللهﷺ، فَقَالَ: مَنْ أَحَقُّ النَّاسِ بِحُسْنِ صَحَابَتِي؟ قَالَ: «أُمُّكَ» قَالَ: ثُمَّ مَنْ؟ قَالَ: «ثُمَّ أُمُّكَ» قَالَ: ثُمَّ مَنْ؟ قَالَ: «ثُمَّ أُمُّكَ» قَالَ: ثُمَّ مَنْ؟ قَالَ: «ثُمَّ أَبُوكَ».', 'ئه‌بوو هوره‌یره‌ -خودێ ژێ رازى بت- دبێژت: زه‌لامه‌ك هاته‌ نك پێغه‌مبه‌رى -سلاڤ لێ بن- و گۆتێ: كیژ ژ مرۆڤ هێژاتره‌ بۆ باشییا هه‌ڤالینییا من؟ وى گۆت: ده‌یكا ته‌، گۆتێ: پاشى كى؟ وى گۆت: پاشى ده‌یكا ته‌، وى گۆت: پاشى كى؟ وى گۆت: پاشى ده‌یكا ته‌، گۆتێ: پاشى كى؟ وى گۆت: پاشى بابێ ته‌.', NULL, true),
  (726, 'دادى د ناڤبەرا عەیالى دا', 'عَنِ النُّعْمَانِ بْنِ بَشِيرٍ رضي الله عنه قَالَ: تَصَدَّقَ عَلَيَّ أَبِي بِبَعْضِ مَالِهِ، فَقَالَتْ أُمِّي عَمْرَةُ بِنْتُ رَوَاحَةَ: لَا أَرْضَى حَتَّى تُشْهِدَ رَسُولَ اللهﷺ، فَانْطَلَقَ أَبِي إِلَى النَّبِيِّﷺ لِيُشْهِدَهُ عَلَى صَدَقَتِي، فَقَالَ لَهُ رَسُولُ اللهﷺ : «أَفَعَلْتَ هَذَا بِوَلَدِكَ كُلِّهِمْ؟» قَالَ: لَا، قَالَ: «اتَّقُوا اللهَ، وَاعْدِلُوا فِي أَوْلَادِكُمْ»، فَرَجَعَ أَبِي، فَرَدَّ تِلْكَ الصَّدَقَةَ.', 'نوعمانێ كوڕێ به‌شیرى -خودێ ژێ رازى بت- دبێژت: بابێ من هنده‌ك مالێ خۆ ب خێر دا من، ئینا ده‌یكا من عه‌مره‌یا كچا ره‌واحه‌یى گۆت: ئه‌ز رازى نابم حه‌تا تو پێغه‌مبه‌رى -سلاڤ لێ بن- بكه‌یه‌ شاهد، هنگى بابێ من چوو نك پێغه‌مبه‌رى -سلاڤ لێ بن- دا وى بكه‌ته‌ شاهد ل سه‌ر وێ خێرا وى دایه‌ من، پێغه‌مبه‌رى -سلاڤ لێ بن- گۆتێ: ته‌ ئه‌ڤ چه‌نده‌ د گه‌ل هه‌مى عه‌یالێ خۆ كرییه‌؟ وى گۆت: نه‌خێر، پێغه‌مبه‌رى -سلاڤ لێ بن- گۆتێ: ژ خودێ بترسن و دادییێ د ناڤبه‌را عه‌یالێ خۆ دا بكه‌ن. ڤێجا بابێ من زڤڕى و ئه‌و خێرا دایه‌ من زڤڕاند.', NULL, true),
  (736, 'یێ ب رەحم نەبت رەحم پێ نائێتەبرن', 'عَنْ أَبِي هُرَيْرَةَ رضي الله عنه أَنَّ الْأَقْرَعَ بْنَ حَابِسٍ، أَبْصَرَ النَّبِيَّﷺ يُقَبِّلُ الحَسَنَ فَقَالَ: إِنَّ لِي عَشَرَةً مِنَ الْوَلَدِ مَا قَبَّلْتُ وَاحِدًا مِنْهُمْ، فَقَالَ رَسُولُ اللهﷺ : «إِنَّهُ مَنْ لَا يَرْحَمْ لَا يُرْحَمْ».', 'ئه‌بوو هوره‌یره‌ -خودێ ژێ رازى بت- دبێژت: ئه‌قره‌عێ كوڕێ حابسى دیت پێغه‌مبه‌ر -سلاڤ لێ بن- یێ حه‌سه‌نى ماچى دكه‌ت، گۆت: من ده‌هـ زارۆك هه‌نه‌ هێشتا من ئێك ژ وان ماچى نه‌كرییه‌، پێغه‌مبه‌رى -سلاڤ لێ بن- گۆت: ئه‌وێ ب ره‌حم نه‌بت ره‌حم پێ نائێته‌برن.', NULL, true),
  (746, 'كەس بلا مەدحێن خۆ نەكەت', 'عَنْ أَبِي هُرَيْرَةَ رضي الله عنه أَنَّ زَيْنَبَ، كَانَ اسْمُهَا بَرَّةَ فَقِيلَ: تُزَكِّي نَفْسَهَا، فَسَمَّاهَا رَسُولُ اللهﷺ زَيْنَبَ.', 'ئه‌بوو هوره‌یره‌ -خودێ ژێ رازى بت- دبێژت: ناڤێ زه‌ینه‌بێ به‌رره‌ بوو (ئانكو: قه‌نجێ) هنده‌كان گۆت: ئه‌و مه‌دحێن خۆ ب قه‌نجییێ دكه‌ت، ئینا پێغه‌مبه‌رى -سلاڤ لێ بن- ناڤێ وێ كره‌ زه‌ینه‌ب.', NULL, true),
  (756, 'دەمێ ل هەوه دبته شەڤ..', 'عن جَابِرِ بْنِ عَبْدِ الله رضي الله عنه يَقُولُ: قَالَ رَسُولُ اللهﷺ : «إِذَا كَانَ جُنْحُ اللَّيْلِ -أَوْ أَمْسَيْتُمْ- فَكُفُّوا صِبْيَانَكُمْ، فَإِنَّ الشَّيْطَانَ يَنْتَشِرُ حِينَئِذٍ، فَإِذَا ذَهَبَ سَاعَةٌ مِنَ اللَّيْلِ فَخَلُّوهُمْ، وَأَغْلِقُوا الْأَبْوَابَ، وَاذْكُرُوا اسْمَ الله، فَإِنَّ الشَّيْطَانَ لَا يَفْتَحُ بَابًا مُغْلَقًا، وَأَوْكُوا قِرَبَكُمْ، وَاذْكُرُوا اسْمَ الله، وَخَمِّرُوا آنِيَتَكُمْ وَاذْكُرُوا اسْمَ الله، وَلَوْ أَنْ تَعْرُضُوا عَلَيْهَا شَيْئًا، وَأَطْفِئُوا مَصَابِيحَكُمْ».', 'جابرێ كوڕێ عه‌بدللاهى -خودێ ژێ رازى بت- دبێژت: پێغه‌مبه‌رى -سلاڤ لێ بن- گۆت: ئه‌گه‌ر ل هه‌وه‌ بوو شه‌ڤ یان ئێڤار، زارۆكێن خۆ بگرن، چونكى شه‌یطان ل وى ده‌مى به‌لاڤ دبن، و گاڤا ده‌مه‌ك ژ شه‌ڤێ چوو ژ نوى وان به‌رده‌ن، و ده‌رگه‌هێن خۆ بگرن، و ناڤێ خودێ بینن، چونكى شه‌یطان وى ده‌رگه‌هى ڤه‌ناكه‌ت یێ هاتبته‌ گرتن، و كونێن ئاڤێ بنخێڤن، و ناڤێ خودێ ل سه‌ر بینن، و ئامانێن خۆ بپه‌چنن، و ناڤێ خودێ ل سه‌ر بینن، ئه‌گه‌ر خۆ هوین تشته‌كى بداننه‌ سه‌ر، و چرایێن خۆ بڤه‌مرینن.', NULL, true),
  (766, 'قەنجییا د گەل عەبدان', 'عَنْ المَعْرُورِ بن سوید قَالَ: لَقِيتُ أَبَا ذَرٍّ رضي الله عنه بِالرَّبَذَةِ وَعَلَيْهِ حُلَّةٌ، وَعَلَى غُلَامِهِ حُلَّةٌ، فَسَأَلْتُهُ عَنْ ذَلِكَ، فَقَالَ: إِنِّي سَابَبْتُ رَجُلًا فَعَيَّرْتُهُ بِأُمِّهِ فَقَالَ لِي النَّبِيُّﷺ : «يَا أَبَا ذَرٍّ أَعَيَّرْتَهُ بِأُمِّهِ؟ إِنَّكَ امْرُؤٌ فِيكَ جَاهِلِيَّةٌ، إِخْوَانُكُمْ خَوَلُكُمْ، جَعَلَهُمْ الله تَحْتَ أَيْدِيكُمْ، فَمَنْ كَانَ أَخُوهُ تَحْتَ يَدِهِ فَلْيُطْعِمْهُ مِمَّا يَأْكُلُ، وَلْيُلْبِسْهُ مِمَّا يَلْبَسُ، وَلَا تُكَلِّفُوهُمْ مَا يَغْلِبُهُمْ، فَإِنْ كلَّفْتُمُوهُمْ فَأَعِينُوهُمْ».', 'مه‌عروورێ كوڕێ سوه‌یدى دبێژت: من ئه‌بوو ذه‌ر -خودێ ژێ رازى بت- ل ره‌به‌ذه‌یێ دیت، كراسه‌ك د به‌ر بوو، و ئێكێ وه‌كى وى د به‌ر عه‌بدێ وى ژى بوو، من پسیارا ڤێ چه‌ندێ ژێ كر، وى گۆت: شه‌ڕه‌ده‌ڤه‌ك د ناڤبه‌را من و زه‌لامه‌كى دا چێبوو، من تان ب ده‌یكا وى دانایێ (ده‌یكا وى جاریه‌ بوو) ئینا پێغه‌مبه‌رى -سلاڤ لێ بن- گۆته‌ من: ئه‌بوو ذه‌ر، تو وى ب ده‌یكا وى كێم دكه‌ى؟ تو مرۆڤه‌كى جاهلییه‌ت ل نك ته‌ هه‌یه‌! ئه‌و برایێن هه‌وه‌نه‌ خودێ كرینه‌ د بن ده‌ستێ هه‌وه‌ڤه‌، ڤێجا هه‌چییێ برایێ وى د بن ده‌ستێ وى ڤه‌ بت بلا خوارنێ ژ وێ بده‌تێ یا ئه‌و دخۆت، و جلكى ژ وێ بكه‌ته‌ به‌ر یا ئه‌و دكه‌ته‌ به‌ر خۆ، و زێده‌تر ژ شیانا وان بارى لێ نه‌كه‌ن، و ئه‌گه‌ر هه‌وه‌ ئه‌و بار لێ كر هوین هارى وان بكه‌ن.', NULL, true),
  (776, 'ئەوێن خێرا وان دوقات', 'عَنْ أَبِي مُوسَى رضي الله عنه قَالَ: قَالَ رَسُولُ اللهﷺ : «ثَلَاثَةٌ لَهُمْ أَجْرَانِ: رَجُلٌ مِنْ أَهْلِ الْكِتَابِ آمَنَ بِنَبِيِّهِ وَآمَنَ بِمُحَمَّدٍﷺ، وَالْعَبْدُ المَمْلُوكُ إِذَا أَدَّى حَقَّ الله وَحَقَّ مَوَالِيهِ، وَرَجُلٌ كَانَتْ عِنْدَهُ أَمَةٌ فَأَدَّبَهَا فَأَحْسَنَ تَأْدِيبَهَا، وَعَلَّمَهَا فَأَحْسَنَ تَعْلِيمَهَا، ثُمَّ أَعْتَقَهَا فَتَزَوَّجَهَا، فَلَهُ أَجْرَانِ».', 'ئه‌بوو مووسا -خودێ ژێ رازى بت- دبێژت: پێغه‌مبه‌رى -سلاڤ لێ بن- گۆت: سێ كه‌س هه‌نه‌ خێرا وان دوقاته‌: زه‌لامه‌كێ كیتابى باوه‌رى ب پێغه‌مبه‌رێ خۆ و ب موحه‌ممه‌دى ژى -سلاڤ لێ بن- ئینابت، و ئه‌و كۆله‌یێ حه‌قێ خودێ و حه‌قێ سه‌ییدێ خۆ ژى ژ سه‌ر خۆ ڕاكه‌ت، و زه‌لامه‌كێ جاریه‌ك هه‌بت ڤێجا ئه‌و وێ تازه‌ تۆره‌ بده‌ت، و باش فێر بكه‌ت، پاشى وێ ئازا كه‌ت و ل خۆ ماره‌ بكه‌ت، ئه‌وى دو خێر بۆ هه‌نه‌.', NULL, true),
  (786, 'كەسێ ژ جهێ وى ڕانەكه', 'عَنِ ابْنِ عُمَرَ رضي الله عنه عَنِ النَّبِيِّﷺ قَالَ: «لَا يُقِيمُ الرَّجُلُ الرَّجُلَ مِنْ مَقْعَدِهِ، ثُمَّ يَجْلِسُ فِيهِ، وَلَكِنْ تَفَسَّحُوا وَتَوَسَّعُوا».', 'عه‌بدللاهێ كوڕێ عومه‌رى -خودێ ژ هه‌ردویان رازى بت- دبێژت: پێغه‌مبه‌رى -سلاڤ لێ بن- گۆت: بلا چو زه‌لام چو زه‌لامێن دى ژ جهێ وى ڕانه‌كه‌ت پاشى ل جهێ وى بڕوینت، به‌لێ جهێ ئێك و دو بكه‌ن.', NULL, true),
  (796, 'مەتەلا هەڤالێ باش و یێ خراب', 'عَنْ أَبِي مُوسَى رضي الله عنه عَنِ النَّبِيِّﷺ قَالَ: «إِنَّمَا مَثَلُ الجَلِيسِ الصَّالِحِ، وَالجَلِيسِ السَّوْءِ، كَحَامِلِ الْمِسْكِ، وَنَافِخِ الْكِيرِ، فَحَامِلُ الْمِسْكِ: إِمَّا أَنْ يُحْذِيَكَ، وَإِمَّا أَنْ تَبْتَاعَ مِنْهُ، وَإِمَّا أَنْ تَجِدَ مِنْهُ رِيحًا طَيِّبَةً، وَنَافِخُ الْكِيرِ: إِمَّا أَنْ يُحْرِقَ ثِيَابَكَ، وَإِمَّا أَنْ تَجِدَ رِيحًا خَبِيثَةً».', 'ئه‌بوو مووسا -خودێ ژێ رازى بت- دبێژت: پێغه‌مبه‌رى -سلاڤ لێ بن- گۆت: مه‌ته‌لا هه‌ڤالێ باش و هه‌ڤالێ خراب (یێ تو ل نك دڕوینى) وه‌كى مه‌ته‌لا هلگرێ مسكێ و خودانێ كویرهێیه‌، هلگرێ مسكێ یان دێ هنده‌كێ ده‌ته‌ ته‌، یان تو دێ ژێ كڕى، یان دێ بێنه‌كا خۆش ژێ سه‌ح كه‌ى، و ئه‌وێ پف دكه‌ته‌ كویرهێ یان دێ كراسێ ته‌ سوژت، یان تو دێ بێنه‌كا نه‌خۆش ژێ سه‌ح كه‌ى.', NULL, true),
  (806, 'ئەو گونەهكارێن نەئێنه عەفیكرن', 'عن أَبَي هُرَيْرَةَ رضي الله عنه يَقُولُ: سَمِعْتُ رَسُولَ اللهﷺ يَقُولُ: «كُلُّ أُمَّتِي مُعَافًى إِلَّا المُجَاهِرِينَ، وَإِنَّ مِنْ المُجَاهَرَةِ أَنْ يَعْمَلَ الرَّجُلُ بِاللَّيْلِ عَمَلًا ثُمَّ يُصْبِحَ وَقَدْ سَتَرَهُ الله عَلَيْهِ فَيَقُولَ: يَا فُلَانُ، عَمِلْتُ الْبَارِحَةَ كَذَا وَكَذَا، وَقَدْ بَاتَ يَسْتُرُهُ رَبُّهُ، وَيُصْبِحُ يَكْشِفُ سِتْرَ الله عَنْهُ».', 'ئه‌بوو هوره‌یره‌ -خودێ ژێ رازى بت- دبێژت: من گوهـ ل پێغه‌مبه‌رى -سلاڤ لێ بن- بوو دگۆت: ل ئوممه‌تا من هه‌مییێ دئێته‌ بۆرین ئه‌و تێ نه‌بن یێن خۆ ئاشكه‌را دكه‌ن، و ژ خۆئاشكه‌راكرنێیه‌ كو زه‌لام ب شه‌ڤ كاره‌كى بكه‌ت و لێ ببته‌ سپێده‌ و خودێ ئه‌و ستاره‌ كربت، ڤێجا بێژت: ئه‌ى فلان، دوهى من هۆ كر و هۆ كر، و ل وى بووبوو شه‌ڤ خودێ ئه‌و ستاره‌ كربوو، سپێدێ ئه‌و ڕادبت ستاره‌یێ خودێ ژ سه‌ر خۆ ڕادكه‌ت.', NULL, true),
  (816, 'بناخەیێن موبایەعەیا صەحابییەكى', 'عَنْ جَرِيرِ بنِ عبدِ الله رضي الله عنه قَالَ: بَايَعْتُ رَسُولَ اللهﷺ عَلَى إِقَامِ الصَّلَاةِ، وَإِيتَاءِ الزَّكَاةِ، وَالنُّصْحِ لِكُلِّ مُسْلِمٍ.', 'جه‌ریرێ كوڕێ عه‌بدللاهى -خودێ ژێ رازى بت- دبێژت: من به‌یعه‌ دا پێغه‌مبه‌رێ خودێ -سلاڤ لێ بن- ل سه‌ر كرنا نڤێژێ، و دانا زه‌كاتێ، و شیره‌تێ بۆ هه‌مى موسلمانان.', NULL, true),
  (826, 'دلۆڤانییا پێغەمبەرى د گەل زارۆكان', 'عن أَنَسِ بْنِ مَالِكٍ رضي الله عنه أَنَّ النَّبِيَّﷺ قَالَ: «إِنِّي لَأَدْخُلُ فِي الصَّلَاةِ وَأَنَا أُرِيدُ إِطَالَتَهَا فَأَسْمَعُ بُكَاءَ الصَّبِيِّ فَأَتَجَوَّزُ فِي صَلَاتِي مِمَّا أَعْلَمُ مِنْ شِدَّةِ وَجْدِ أُمِّهِ مِنْ بُكَائِهِ».', 'ئه‌نه‌سێ كوڕێ مالكى -خودێ ژێ رازى بت- دبێژت: پێغه‌مبه‌رى -سلاڤ لێ بن- گۆت: ئه‌ز دچمه‌ د نڤێژێ دا و من دڤێت ئه‌ز وێ درێژ بكه‌م، به‌لێ من گوهـ ل گرییا زارۆكى دبت ڤێجا ئه‌ز له‌زێ ل نڤێژا خۆ دكه‌م ژ به‌ر كو ئه‌ز دزانم چه‌ند دلێ ده‌یكا وى یێ ب دویڤ وى ڕا ژ به‌ر گرییا وى.', NULL, true),
  (836, 'دڤێت ئیمام نڤێژێ زێده درێژ نەكەت', 'عَنْ أَبِي هُرَيْرَةَ رضي الله عنه أَنَّ النَّبِيَّﷺ قَالَ: «إِذَا أَمَّ أَحَدُكُمُ النَّاسَ، فَلْيُخَفِّفْ، فَإِنَّ فِيهِمُ الصَّغِيرَ، وَالْكَبِيرَ، وَالضَّعِيفَ، وَالمَرِيضَ، فَإِذَا صَلَّى وَحْدَهُ فَلْيُصَلِّ كَيْفَ شَاءَ».', 'ئه‌بوو هوره‌یره‌ -خودێ ژێ رازى بت- دبێژت: پێغه‌مبه‌رى -سلاڤ لێ بن- گۆت: ئه‌گه‌ر ئێك ژ هه‌وه‌ نڤێژ ل به‌را مرۆڤان كر بلا نڤێژێ سڤك بكه‌ت، چونكى د ناڤ وان دا یێ بچویك و مه‌زن و لاواز و نه‌خۆش هه‌یه‌، و چى گاڤا وى ب تنێ نڤێژ كر وى چاوا دڤێت بلا وه‌سا نڤێژێ بكه‌ت.', NULL, true),
  (846, 'ڕەنگەكێ خۆمەزنكرنێ', 'عَنْ عَبْدِ اللهِ بْنِ عُمَرَ رضي الله عنه قَالَ: قَالَ رَسُولُ اللهﷺ : «مَنْ جَرَّ ثَوْبَهُ خُيَلاَءَ لَمْ يَنْظُرِ الله إِلَيْهِ يَوْمَ الْقِيَامَةِ» فَقَالَ أَبُو بَكْرٍ: إِنَّ أَحَدَ شِقَّيْ ثَوْبِي يَسْتَرْخِي إِلاَّ أَنْ أَتَعَاهَدَ ذَلِكَ مِنْهُ، فَقَالَ رَسُولُ اللهﷺ : «إِنَّكَ لَسْتَ تَصْنَعُ ذَلِكَ خُيَلاَءَ».', 'عه‌بدللاهێ كوڕێ عومه‌رى -خودێ ژ هه‌ردویان رازى بت- دبێژت: پێغه‌مبه‌رى -سلاڤ لێ بن- گۆت: هه‌چییێ بۆ خۆمه‌زنكرن كراسێ خۆ ب دویڤ خۆ ڕا بكێشت خودێ ڕۆژا قیامه‌تێ به‌رێ خۆ ناده‌تێ. ئه‌بوو به‌كرى گۆت: ڕه‌خه‌كێ كراسێ من شۆڕ دبت ئه‌گه‌ر ئه‌ز وى هل نه‌ده‌م، پێغه‌مبه‌رى -سلاڤ لێ بن- گۆت: تو وێ چه‌ندێ بۆ خۆمه‌زنكرنێ ناكه‌ى.', NULL, true),
  (856, 'دورستییا یاریكرنێ', 'عَنْ أَبِي هُرَيْرَةَ رضي الله عنه قَالَ: بَيْنَمَا الحَبَشَةُ يَلْعَبُونَ عِنْدَ رَسُولِ اللهﷺ بِحِرَابِهِمْ، إِذْ دَخَلَ عُمَرُ بْنُ الخَطَّابِ، فَأَهْوَى إِلَى الحَصْبَاءِ يَحْصِبُهُمْ بِهَا، فَقَالَ لَهُ رَسُولُ اللهﷺ : «دَعْهُمْ يَا عُمَرُ».', 'ئه‌بوو هوره‌یره‌ -خودێ ژێ رازى بت- دبێژت: ده‌مه‌كى حه‌به‌شییان ل نك پێغه‌مبه‌رى -سلاڤ لێ بن- یارى ب ڕمێن خۆ دكرن، عومه‌رێ كوڕێ خه‌ططابى هاته‌ وێڕێ، و وى ده‌ست دا هنده‌ك به‌ركان و د وان وه‌ركرن، ئینا پێغه‌مبه‌رى -سلاڤ لێ بن- گۆتێ: وان بهێله‌ عومه‌ر.', NULL, true),
  (866, 'خێرا قەنجییا د گەل حەیوانى', 'عَنْ أَبِي هُرَيْرَةَ رضي الله عنه أَنَّ رَسُولَ اللهﷺ قَالَ: «بَيْنَمَا رَجُلٌ يَمْشِي بِطَرِيقٍ اشْتَدَّ عَلَيْهِ الْعَطَشُ، فَوَجَدَ بِئْرًا، فَنَزَلَ فِيهَا فَشَرِبَ، ثُمَّ خَرَجَ فَإِذَا كَلْبٌ يَلْهَثُ يَأْكُلُ الثَّرَى مِنَ الْعَطَشِ، فَقَالَ الرَّجُلُ: لَقَدْ بَلَغَ هَذَا الْكَلْبَ مِنَ الْعَطَشِ مِثْلُ الَّذِي كَانَ بَلَغَ مِنِّي، فَنَزَلَ الْبِئْرَ فَمَلَأَ خُفَّهُ مَاءً، ثُمَّ أَمْسَكَهُ بِفِيهِ حَتَّى رَقِيَ فَسَقَى الْكَلْبَ فَشَكَرَ اللهُ لَهُ فَغَفَرَ لَهُ» قَالُوا: يَا رَسُولَ الله وَإِنَّ لَنَا فِي هَذِهِ الْبَهَائِمِ لَأَجْرًا؟ فَقَالَ: «فِي كُلِّ كَبِدٍ رَطْبَةٍ أَجْرٌ».', 'ئه‌بوو هوره‌یره‌ -خودێ ژێ رازى بت- دبێژت: پێغه‌مبه‌رى -سلاڤ لێ بن- گۆت: ده‌مه‌كى زه‌لامه‌ك ل ڕێكه‌كێ دچوو زێده‌ تێنى بوو، و وى بیره‌ك دیت، چوو خوارێ و ئاڤ ژێ ڤه‌خوار، پاشى ده‌ركه‌فت، هنگى وى صه‌یه‌ك دیت ئه‌زمان د ده‌ڤى دا هاتبوو، ژ تێنا دا بێن دكره‌ ئاخێ، زه‌لامى گۆت: ئه‌ڤه‌ ژى وه‌كى من یێ تێنى بووى، ئینا ئه‌و چوو د بیرێ دا و خوفكا خۆ تژى ئاڤ كر و كره‌ د ده‌ڤێ خۆ دا حه‌تا ب سه‌ر كه‌فتى، و صه‌ ئاڤداى، ئینا خودێ كارێ وى قه‌بویل كر و گونه‌هێن وى بۆ ژێبرن، گۆتن: ئه‌ى پێغه‌مبه‌ر، ما د حه‌یوانان ژى دا خێر بۆ مه‌ هه‌یه‌؟ وى گۆت: د هه‌ر خودان مێلاكه‌كا ته‌ڕ دا خێر هه‌یه‌.', NULL, true),
  (876, 'گونەها ئازاردانا حەیوانى', 'عَنْ عَبْدِ الله بن عمر رضي الله عنه أَنَّ رَسُولَ اللهﷺ قَالَ: «عُذِّبَتِ امْرَأَةٌ فِي هِرَّةٍ سَجَنَتْهَا حَتَّى مَاتَتْ فَدَخَلَتْ فِيهَا النَّارَ، لَا هِيَ أَطْعَمَتْهَا وَسَقَتْهَا، إِذْ حَبَسَتْهَا، وَلَا هِيَ تَرَكَتْهَا تَأْكُلُ مِنْ خَشَاشِ الْأَرْضِ».', 'عه‌بدللاهێ كوڕێ عومه‌رى -خودێ ژ هه‌ردویان رازى بت- دبێژت: پێغه‌مبه‌رى -سلاڤ لێ بن- گۆت: ژنه‌ك هاته‌ عه‌زابدان ژ به‌ر پشیكه‌كێ وێ ئه‌و گرتبوو حه‌تا مرى ڤێجا ئه‌و ژ به‌ر وێ چوو ئاگرى، ژ به‌ر كو وێ ئه‌و گرتبوو وێ نه‌ خوارن نه‌ ڤه‌خوارن نه‌دایێ، و نه‌هێلا ئه‌و بچت ژ كه‌سكاتییێ عه‌ردى بخۆت.', NULL, true),
  (886, 'حەرامییا (حیلێن شەرعى!)', 'عَنْ جَابِرِ بْنِ عَبْدِ الله رضي الله عنه أَنَّهُ سَمِعَ رَسُولَ اللهﷺ يَقُولُ عَامَ الْفَتْحِ وَهُوَ بِمَكَّةَ: «إِنَّ اللهَ وَرَسُولَهُ حَرَّمَ بَيْعَ الخَمْرِ، وَالمَيْتَةِ، وَالْخِنْزِيرِ، وَالْأَصْنَامِ»، فَقِيلَ: يَا رَسُولَ الله، أَرَأَيْتَ شُحُومَ المَيْتَةِ، فَإِنَّهُ يُطْلَى بِهَا السُّفُنُ، وَيُدْهَنُ بِهَا الجُلُودُ، وَيَسْتَصْبِحُ بِهَا النَّاسُ، فَقَالَ: «لَا، هُوَ حَرَامٌ»، ثُمَّ قَالَ رَسُولُ اللهﷺ عِنْدَ ذَلِكَ: «قَاتَلَ اللهُ الْيَهُودَ، إِنَّ اللهَ عَزَّ وَجَلَّ لَمَّا حَرَّمَ عَلَيْهِمْ شُحُومَهَا أَجْمَلُوهُ، ثُمَّ بَاعُوهُ فَأَكَلُوا ثَمَنَهُ».', 'جابرێ كوڕێ عه‌بدللاهى -خودێ ژێ رازى بت- دبێژت: ل سالا ڤه‌كرنا مه‌كه‌هێ من ل مه‌كه‌هێ گوهـ ل پێغه‌مبه‌رى -سلاڤ لێ بن- بوو دگۆت: هندى خودێ و پێغه‌مبه‌رێ وییه‌ فرۆتنا مه‌یێ و مرارى و به‌رازى و صه‌نه‌مان حه‌رامكرییه‌. گۆتن: ئه‌ى پێغه‌مبه‌رێ خودێ، تو چ دبێژى بۆ به‌زێ مراران، ئه‌وى د گه‌مییان دده‌ن، و چه‌رمى پێ دۆن دده‌ن، و خه‌لك وى بۆ چرایان ب كار دئینت؟ پێغه‌مبه‌رى -سلاڤ لێ بن- گۆت: نه‌ ئه‌و حه‌رامه‌، پاشى گۆت: خودێ جوهییان بكوژت! ده‌مێ خودێ به‌زێ مراران ل سه‌ر وان حه‌رامكرى وان ئه‌و حه‌لاند پاشى فرۆت و پارێ وى خوار.', NULL, true);
INSERT INTO gencine_hadiths (sort_order, title, ar, ku, source, active) VALUES
  (896, 'حەرامییا مەیێ', 'عَنِ ابْنِ عُمَرَ رضي الله عنه قَالَ: قَالَ رَسُولُ اللهﷺ : «كُلُّ مُسْكِرٍ خَمْرٌ، وَكُلُّ مُسْكِرٍ حَرَامٌ، وَمَنْ شَرِبَ الخَمْرَ فِي الدُّنْيَا فَمَاتَ وَهُوَ يُدْمِنُهَا لَمْ يَتُبْ، لَمْ يَشْرَبْهَا فِي الْآخِرَةِ».', 'عه‌بدللاهێ كوڕێ عومه‌رى -خودێ ژ هه‌ردویان رازى بت- دبێژت: پێغه‌مبه‌رى -سلاڤ لێ بن- گۆت: هه‌ر ڤه‌خوارنه‌كا عه‌قلى ببه‌ت مه‌یه‌، و هه‌ر ڤه‌خوارنه‌كا عه‌قلى ببه‌ت حه‌رامه‌، و هه‌چییێ مه‌یێ ل دنیایێ ڤه‌خۆت و بمرت و ئه‌و وێ ڤه‌دخۆت و تۆبه‌ نه‌كه‌ت، ئه‌و وێ ل ئاخره‌تێ ڤه‌ناخۆت.', NULL, true),
  (906, 'بێنفرەهییا پێغەمبەرى', 'عن عَبْدِ الله بن مسعود رضي الله عنه قَالَ: قَسَمَ النَّبِيُّﷺ قَسْمًا، فَقَالَ رَجُلٌ: إِنَّ هَذِهِ لَقِسْمَةٌ مَا أُرِيدَ بِهَا وَجْهُ الله! فَأَتَيْتُ النَّبِيَّﷺ فَأَخْبَرْتُهُ، فَغَضِبَ حَتَّى رَأَيْتُ الْغَضَبَ في وَجْهِهِ، ثُمَّ قَالَ: «يَرْحَمُ اللَّهَ مُوسَى قَدْ أُوذِيَ بِأَكْثَرَ مِنْ هَذَا فَصَبَرَ».', 'عه‌بدللاهێ كوڕێ مه‌سعوودى -خودێ ژێ رازى بت- دبێژت: پێغه‌مبه‌رى -سلاڤ لێ بن- ماله‌ك لێكڤه‌كر، ئینا زه‌لامه‌كى گۆت: ئه‌ڤه‌ لێكڤه‌كرنه‌كه‌ مه‌خسه‌د پێ كنارێ خودێ نه‌بوویه‌! ئه‌ز هاتم من ئه‌و گۆتن بۆ پێغه‌مبه‌رى -سلاڤ لێ بن- ڤه‌گێڕا، كه‌ربێن وى ڤه‌بوون حه‌تا من ئه‌و د دێمێ وى دا دیتى، پاشى گۆت: خودێ ره‌حمێ ب مووسایى ببه‌ت، ئه‌و ژ ڤێ پتر هاته‌ ئێشاندن و وى صه‌بر كێشا.', NULL, true),
  (916, NULL, 'عَنْ أَنَسِ بْنِ مَالِكٍ رضي الله عنه قَالَ: كُنْتُ أَمْشِي مَعَ رَسُولِ اللهﷺ، وَعَلَيْهِ رِدَاءٌ نَجْرَانِيٌّ غَلِيظُ الحَاشِيَةِ، فَأَدْرَكَهُ أَعْرَابِيٌّ، فَجَبَذَهُ بِرِدَائِهِ جَبْذَةً شَدِيدَةً، نَظَرْتُ إِلَى صَفْحَةِ عُنُقِ رَسُولِ اللهﷺ وَقَدْ أَثَّرَتْ بِهَا حَاشِيَةُ الرِّدَاءِ، مِنْ شِدَّةِ جَبْذَتِهِ، ثُمَّ قَالَ: يَا مُحَمَّدُ مُرْ لِي مِنْ مَالِ الله الَّذِي عِنْدَكَ، فَالْتَفَتَ إِلَيْهِ رَسُولُ اللهﷺ فَضَحِكَ، ثُمَّ أَمَرَ لَهُ بِعَطَاءٍ.', 'ئه‌نه‌سێ كوڕێ مالكى -خودێ ژێ رازى بت- دبێژت: ئه‌ز د گه‌ل پێغه‌مبه‌رى -سلاڤ لێ بن- دچووم، و كراسه‌كێ نه‌جرانى یێ لێڤ خه‌رجیكرى د به‌ر بوو، ئه‌عرابییه‌ك ڤێڕا گه‌هشت و ب دژوارى كراسێ وى كێشا، حه‌تا من ستویێ پێغه‌مبه‌رى -سلاڤ لێ بن- دیت لێڤا كراسێ وى تێدا چوو خوار، پاشى وى ئه‌عرابى گۆت: هنده‌كێ ژ مالێ خودێ یێ ل نك ته‌ هه‌ى بده‌ من، پێغه‌مبه‌ر -سلاڤ لێ بن- لێ زڤڕى و كه‌نى و فه‌رمان دا هنده‌ك مالى بده‌نێ.', NULL, true),
  (926, 'عەزابا ڕەنگەكێ منافقان', 'عَنْ أُسَامَةَ بْنِ زَيْدٍ رضي الله عنه قال: سَمِعْتُ رَسُولَ اللهﷺ يَقُولُ: «يُؤْتَى بِالرَّجُلِ يَوْمَ الْقِيَامَةِ، فَيُلْقَى فِي النَّارِ، فَتَنْدَلِقُ أَقْتَابُ بَطْنِهِ، فَيَدُورُ بِهَا كَمَا يَدُورُ الْحِمَارُ بِالرَّحَى، فَيَجْتَمِعُ إِلَيْهِ أَهْلُ النَّارِ، فَيَقُولُونَ: يَا فُلَانُ مَا لَكَ؟ أَلَمْ تَكُنْ تَأْمُرُ بِالمَعْرُوفِ، وَتَنْهَى عَنِ المُنْكَرِ؟ فَيَقُولُ: بَلَى، قَدْ كُنْتُ آمُرُ بِالمَعْرُوفِ وَلَا آتِيهِ، وَأَنْهَى عَنِ المُنْكَرِ وَآتِيهِ».', 'ئوسامه‌یێ كوڕێ زه‌یدى -خودێ ژ هه‌ردویان رازى بت- دبێژت: من گوهـ ل پێغه‌مبه‌رى -سلاڤ لێ بن- بوو دگۆت: ڕۆژا قیامه‌تێ زه‌لامه‌كى دئینن دهاڤێنه‌ د ئاگرى دا، ڤێجا ڕویڤیكێن وى دكه‌ڤن و ئه‌و ل دۆر دزڤڕت كانێ چاوا كه‌ر ل دۆر جه‌نجه‌رێ دزڤڕت، ڤێجا جه‌هنه‌مى لێ كۆم دبن و دبێژن: فلان! ته‌ خێره‌؟ ما ته‌ فه‌رمان ب باشییێ نه‌دكر و ته‌ پاشڤه‌برن ژ خرابییێ نه‌دكر؟ ئه‌و دێ بێژت: به‌لێ من فه‌رمان ب باشییێ دكر و من ئه‌و نه‌دكر، و من پاشڤه‌برن ژ خرابییێ دكر و من ئه‌و دكر.', NULL, true),
  (936, 'فرەهییا رەحما خودێ', 'عن أَبي هُرَيْرَةَ رضي الله عنه قَالَ: سَمِعْتُ النَّبِيَّﷺ قَالَ: «إِنَّ عَبْدًا أَصَابَ ذَنْبًا -وَرُبَّمَا قَالَ: أَذْنَبَ ذَنْبًا- فَقَالَ: رَبِّ أَذْنَبْتُ -وَرُبَّمَا قَالَ أَصَبْتُ- فَاغْفِرْ لِي، فَقَالَ رَبُّهُ: أَعَلِمَ عَبْدِي أَنَّ لَهُ رَبًّا يَغْفِرُ الذَّنْبَ وَيَأْخُذُ بِهِ؟ غَفَرْتُ لِعَبْدِي، ثُمَّ مَكَثَ مَا شَاءَ الله، ثُمَّ أَصَابَ ذَنْبًا -أَوْ أَذْنَبَ ذَنْبًا- فَقَالَ: رَبِّ أَذْنَبْتُ -أَوْ أَصَبْتُ- آخَرَ فَاغْفِرْهُ، فَقَالَ: أَعَلِمَ عَبْدِي أَنَّ لَهُ رَبًّا يَغْفِرُ الذَّنْبَ وَيَأْخُذُ بِهِ؟ غَفَرْتُ لِعَبْدِي، ثُمَّ مَكَثَ مَا شَاءَ الله، ثُمَّ أَذْنَبَ ذَنْبًا -وَرُبَّمَا قَالَ أَصَابَ ذَنْبًا- قَالَ: رَبِّ أَصَبْتُ -أَوْ قَالَ أَذْنَبْتُ- آخَرَ فَاغْفِرْهُ لِي، فَقَالَ: أَعَلِمَ عَبْدِي أَنَّ لَهُ رَبًّا يَغْفِرُ الذَّنْبَ وَيَأْخُذُ بِهِ؟ غَفَرْتُ لِعَبْدِي –ثَلَاثًا- فَلْيَعْمَلْ مَا شَاءَ».', 'ئه‌بوو هوره‌یره‌ -خودێ ژێ رازى بت- دبێژت: من گوهـ ل پێغه‌مبه‌رى -سلاڤ لێ بن- بوو دگۆت: عه‌بده‌كى گونه‌هه‌ك كر و گۆت: یا ره‌بى من گونه‌هه‌ك كر تو من بغه‌فرینه‌، ئینا خودایێ وى گۆت: ئه‌رێ عه‌بدێ من زانى كو وى خودایه‌ك هه‌یه‌ گونه‌هێ ژێ دبه‌ت و پێ دگرت؟ من عه‌بدێ خۆ غه‌فراند، پاشى هندى خودێ حه‌زكرى ئه‌و ما، پاشى وى گونه‌هه‌ك كر و گۆت: یا ره‌بى من گونه‌هه‌كا دى كر تو من بغه‌فرینه‌، ئینا خودایێ وى گۆت: ئه‌رێ عه‌بدێ من زانى كو وى خودایه‌ك هه‌یه‌ گونه‌هێ ژێ دبه‌ت و پێ دگرت؟ من عه‌بدێ خۆ غه‌فراند، پاشى هندى خودێ حه‌زكرى ئه‌و ما، پاشى وى گونه‌هه‌كا دى كر و گۆت: یا ره‌بى من گونه‌هه‌ك كر تو من بغه‌فرینه‌، ئینا خودایێ وى گۆت: ئه‌رێ عه‌بدێ من زانى كو وى خودایه‌ك هه‌یه‌ گونه‌هێ ژێ دبه‌ت و پێ دگرت؟ من عه‌بدێ خۆ غه‌فراند -سێ جاران- ڤێجا وى چ دڤێت بلا بكه‌ت.', NULL, true);
